import { Team, Round, Match, MatchStatus, RoundStatus } from '../types';

export function generateSchedule(
  teams: Team[],
  numberOfCourts: number
): Round[] {
  const teamIds = teams.map(t => t.id);
  const isOdd = teamIds.length % 2 !== 0;
  if (isOdd) {
    teamIds.push('BYE');
  }

  const numTeams = teamIds.length;
  const numRounds = numTeams - 1;
  const half = numTeams / 2;

  const rounds: Round[] = [];

  for (let r = 0; r < numRounds; r++) {
    const roundMatches: Match[] = [];

    for (let i = 0; i < half; i++) {
      const teamA = teamIds[i];
      const teamB = teamIds[numTeams - 1 - i];

      // Exclude true BYEs from the match list but they represent a logic step
      if (teamA !== 'BYE' && teamB !== 'BYE') {
        roundMatches.push({
          id: `round-${r}-match-${i}`,
          courtNumber: 0, // Assigned below
          teamAId: teamA,
          teamBId: teamB,
          scoreA: 0,
          scoreB: 0,
          status: MatchStatus.PENDING,
        });
      }
    }

    // Assign courts and waves
    roundMatches.forEach((match, index) => {
      match.courtNumber = (index % numberOfCourts) + 1;
      match.waveNumber = Math.floor(index / numberOfCourts) + 1;
    });

    rounds.push({
      id: `round-${r}`,
      roundNumber: r + 1,
      status: RoundStatus.NOT_STARTED,
      elapsedSeconds: 0,
      matches: roundMatches
    });

    // Rotate circle
    const last = teamIds.pop();
    if (last) {
      teamIds.splice(1, 0, last);
    }
  }

  return rounds;
}

import { Event, StandingRow, MatchStatus, RoundStatus } from '../types';

export function computeStandings(event: Event): StandingRow[] {
  const standings: Record<string, StandingRow> = {};

  // Initialize
  event.teams.forEach(team => {
    standings[team.id] = {
      rank: 0,
      teamId: team.id,
      teamName: team.name,
      wins: 0,
      losses: 0,
      pointsFor: 0,
      pointsAgainst: 0,
      diff: 0,
      gamesPlayed: 0,
      byeCount: 0
    };
  });

  // Process all submitted matches
  event.rounds.forEach(round => {
    if (round.status === RoundStatus.SUBMITTED) {
      round.matches.forEach(match => {
        if (match.status === MatchStatus.COMPLETE) {
          const tA = standings[match.teamAId];
          const tB = standings[match.teamBId];

          if (tA && tB) {
            tA.gamesPlayed++;
            tB.gamesPlayed++;
            tA.pointsFor += match.scoreA;
            tA.pointsAgainst += match.scoreB;
            tB.pointsFor += match.scoreB;
            tB.pointsAgainst += match.scoreA;

            if (match.scoreA > match.scoreB) {
              tA.wins++;
              tB.losses++;
            } else if (match.scoreB > match.scoreA) {
              tB.wins++;
              tA.losses++;
            }
          }
        }
      });
    }
  });

  // Calculate differentials
  Object.values(standings).forEach(s => {
    s.diff = s.pointsFor - s.pointsAgainst;
  });

  // Sort with tie-breakers
  const sorted = Object.values(standings).sort((a, b) => {
    // 1. Wins
    if (b.wins !== a.wins) return b.wins - a.wins;
    // 2. Point Diff
    if (b.diff !== a.diff) return b.diff - a.diff;
    // 3. Points For
    if (b.pointsFor !== a.pointsFor) return b.pointsFor - a.pointsFor;
    // Stability
    return a.teamName.localeCompare(b.teamName);
  });

  // Assign ranks
  return sorted.map((s, i) => ({ ...s, rank: i + 1 }));
}

import { Event } from '../types';

const STORAGE_KEY = 'pb_events_v1';

export function saveEvent(event: Event) {
  const events = getStoredEvents();
  events[event.id] = event;
  localStorage.setItem(STORAGE_KEY, JSON.stringify(events));
}

export function getStoredEvents(): Record<string, Event> {
  const data = localStorage.getItem(STORAGE_KEY);
  return data ? JSON.parse(data) : {};
}

export function getEvent(id: string): Event | null {
  const events = getStoredEvents();
  return events[id] || null;
}

export function generateEventShareUrl(event: Event): string {
  // In a real app, this would use a backend. 
  // For this prototype, we'll use hash routing.
  return `${window.location.origin}${window.location.pathname}#/event/${event.id}`;
}

export function setHostToken(eventId: string, token: string) {
  localStorage.setItem(`host_token_${eventId}`, token);
}

export function getHostToken(eventId: string): string | null {
  return localStorage.getItem(`host_token_${eventId}`);
}

import React, { useState, useEffect, useCallback } from 'react';
import { 
  Plus, 
  Share2, 
  Settings, 
  Trophy, 
  ChevronRight, 
  ChevronLeft, 
  Play, 
  Square, 
  RotateCcw, 
  Edit3,
  Users,
  LayoutGrid
} from 'lucide-react';
import { nanoid } from 'nanoid';
import { Event, Team, Round, Match, RoundStatus, MatchStatus, StandingRow } from './types';
