// --- Components ---

const Button: React.FC<{
  onClick?: () => void;
  children: React.ReactNode;
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost';
  className?: string;
  disabled?: boolean;
  type?: 'button' | 'submit';
}> = ({ onClick, children, variant = 'primary', className = '', disabled, type = 'button' }) => {
  const baseClasses = "px-6 py-3 rounded-xl font-semibold transition-all flex items-center justify-center gap-2 active:scale-95 disabled:opacity-50 disabled:active:scale-100";
  const variants = {
    primary: "bg-[#0984e3] text-white shadow-lg shadow-blue-200",
    secondary: "bg-white text-gray-800 border border-gray-200",
    danger: "bg-red-500 text-white shadow-lg shadow-red-200",
    ghost: "bg-transparent text-gray-600 hover:bg-gray-100"
  };

  return (
    <button type={type} onClick={onClick} className={`${baseClasses} ${variants[variant]} ${className}`} disabled={disabled}>
      {children}
    </button>
  );
};

// --- Views ---

const LandingView: React.FC<{ onCreate: () => void; onResume: (id: string) => void }> = ({ onCreate, onResume }) => {
  const history = Object.values(getStoredEvents()).sort((a, b) => b.createdAt - a.createdAt).slice(0, 3);

  return (
    <div className="flex flex-col items-center justify-center min-h-[80vh] px-6 text-center">
      <div className="mb-12">
        <h1 className="text-5xl font-black text-white mb-4 drop-shadow-md">COASTAL PICKLE</h1>
        <p className="text-lg text-white font-medium opacity-90">Instant round robins for the shoreline.</p>
      </div>

      <div className="w-full max-w-sm space-y-4">
        <Button onClick={onCreate} className="w-full text-xl py-6">
          <Plus size={24} /> Create Round Robin
        </Button>

        <Button onClick={() => {
          if (navigator.share) {
            navigator.share({ title: 'Coastal Pickle', url: window.location.href });
          }
        }} variant="secondary" className="w-full">
          <Share2 size={20} /> Share App
        </Button>
      </div>

      {history.length > 0 && (
        <div className="mt-16 w-full max-w-sm">
          <h2 className="text-white font-bold mb-4 uppercase tracking-widest text-sm opacity-80">Recent Events</h2>
          <div className="space-y-3">
            {history.map(ev => (
              <button 
                key={ev.id} 
                onClick={() => onResume(ev.id)}
                className="w-full bg-white/20 backdrop-blur-md p-4 rounded-2xl flex items-center justify-between text-white hover:bg-white/30 transition-colors"
              >
                <div className="text-left">
                  <div className="font-bold">{ev.name}</div>
                  <div className="text-xs opacity-70">{ev.numberOfTeams} Teams • {new Date(ev.createdAt).toLocaleDateString()}</div>
                </div>
