const CreateView: React.FC<{ onCreated: (ev: Event) => void; onBack: () => void }> = ({ onCreated, onBack }) => {
  const [name, setName] = useState('Coastal Classic');
  const [teams, setTeams] = useState(6);
  const [courts, setCourts] = useState(2);
  const [pts, setPts] = useState(11);
  const [winBy2, setWinBy2] = useState(true);

  // Auto-adjust courts if they exceed teams/2
  useEffect(() => {
    if (courts > Math.floor(teams / 2)) {
      setCourts(Math.floor(teams / 2) || 1);
    }
  }, [teams, courts]);

  const handleCreate = () => {
    const hostToken = nanoid();
    const event: Event = {
      id: nanoid(10),
      name,
      createdAt: Date.now(),
      hostToken,
      hostPasscode: '1234', // Simple default
      numberOfTeams: teams,
      numberOfCourts: courts,
      pointsPerGame: pts,
      winBy2,
      scoringType: 'TRADITIONAL',
      teams: [],
      rounds: []
    };
    setHostToken(event.id, hostToken);
    onCreated(event);
  };

  return (
    <div className="max-w-md mx-auto p-6 animate-in fade-in slide-in-from-bottom-4">
      <header className="flex items-center gap-4 mb-8">
        <button onClick={onBack} className="p-2 bg-white/20 rounded-full text-white"><ChevronLeft size={24} /></button>
        <h1 className="text-2xl font-bold text-white">Event Setup</h1>
      </header>

      <div className="glass-card rounded-3xl p-6 space-y-6">
        <div>
          <label className="block text-sm font-bold text-gray-500 uppercase mb-2">Event Name</label>
          <input 
            type="text" 
            value={name}
            onChange={e => setName(e.target.value)}
            className="w-full p-4 rounded-xl border-2 border-gray-100 focus:border-[#0984e3] outline-none font-semibold"
            placeholder="e.g. Saturday Smash"
          />
        </div>

        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-bold text-gray-500 uppercase mb-2">Teams ({teams})</label>
            <input 
              type="range" min="2" max="24" value={teams} 
              onChange={e => setTeams(parseInt(e.target.value))}
              className="w-full accent-[#0984e3]" 
            />
          </div>
          <div>
            <label className="block text-sm font-bold text-gray-500 uppercase mb-2">Courts ({courts})</label>
            <input 
              type="range" min="1" max="12" value={courts} 
              onChange={e => setCourts(parseInt(e.target.value))}
              className="w-full accent-[#0984e3]" 
            />
          </div>
        </div>

        <div className="flex items-center justify-between p-4 bg-gray-50 rounded-2xl">
          <div className="font-bold">Win By 2</div>
          <input 
            type="checkbox" 
            checked={winBy2} 
            onChange={e => setWinBy2(e.target.checked)}
            className="w-6 h-6 accent-[#0984e3]" 
          />
        </div>

        <div>
          <label className="block text-sm font-bold text-gray-500 uppercase mb-2">Points Per Game</label>
          <div className="flex gap-2">
            {[11, 15, 21].map(v => (
              <button 
                key={v}
                onClick={() => setPts(v)}
                className={`flex-1 py-3 rounded-xl font-bold transition-all ${pts === v ? 'bg-[#0984e3] text-white' : 'bg-gray-100 text-gray-500'}`}
              >
                {v}
              </button>
            ))}
          </div>
        </div>

        <Button onClick={handleCreate} className="w-full py-4 text-lg mt-4" disabled={!name}>
          Next: Add Teams
        </Button>
      </div>
    </div>
  );
};

const TeamSetupView: React.FC<{ event: Event; onConfirm: (teams: Team[]) => void }> = ({ event, onConfirm }) => {
  const [teams, setTeams] = useState<Team[]>(
    Array.from({ length: event.numberOfTeams }, (_, i) => ({
      id: nanoid(),
      name: `Team ${i + 1}`,
      player1: '',
      player2: ''
    }))
  );

  const updateTeam = (idx: number, field: keyof Team, val: string) => {
    const next = [...teams];
    next[idx] = { ...next[idx], [field]: val };
    setTeams(next);
  };

  const isReady = teams.every(t => t.name && t.player1 && t.player2);

  return (
    <div className="max-w-md mx-auto p-6">
      <header className="mb-8">
        <h1 className="text-3xl font-bold text-white">Roster</h1>
        <p className="text-white/80">Enter player names for {event.numberOfTeams} teams.</p>
      </header>

      <div className="space-y-4 mb-24">
        {teams.map((team, i) => (
          <div key={team.id} className="glass-card rounded-2xl p-5">
            <div className="flex items-center justify-between mb-4">
              <span className="bg-gray-800 text-white px-3 py-1 rounded-full text-xs font-bold">TEAM {i + 1}</span>
              <input 
                type="text" 
                value={team.name}
                onChange={e => updateTeam(i, 'name', e.target.value)}
                className="text-right font-bold text-lg focus:outline-none bg-transparent"
              />
            </div>
            <div className="space-y-3">
              <input 
                type="text" placeholder="Player 1" 
                value={team.player1}
                onChange={e => updateTeam(i, 'player1', e.target.value)}
                className="w-full p-3 rounded-lg border border-gray-100 focus:border-[#0984e3] outline-none"
              />
              <input 
                type="text" placeholder="Player 2" 
                value={team.player2}
                onChange={e => updateTeam(i, 'player2', e.target.value)}
                className="w-full p-3 rounded-lg border border-gray-100 focus:border-[#0984e3] outline-none"
              />
            </div>
          </div>
        ))}
      </div>

      <div className="fixed bottom-0 left-0 right-0 p-6 glass-card border-t border-white/20">
        <Button onClick={() => onConfirm(teams)} className="w-full py-4 text-lg" disabled={!isReady}>
          Generate Schedule
        </Button>
      </div>
    </div>
  );
};

const Dashboard: React.FC<{ 
  event: Event; 
  onUpdate: (ev: Event) => void;
  isHost: boolean;
}> = ({ event, onUpdate, isHost }) => {
  const [activeRoundIdx, setActiveRoundIdx] = useState(0);
  const [showStandings, setShowStandings] = useState(false);
  const [currentTime, setCurrentTime] = useState(Date.now());

  const currentRound = event.rounds[activeRoundIdx];
  const standings = computeStandings(event);

  useEffect(() => {
    const interval = setInterval(() => setCurrentTime(Date.now()), 1000);
    return () => clearInterval(interval);
  }, []);

  const getTimerDisplay = (round: Round) => {
    let seconds = round.elapsedSeconds;
    if (round.status === RoundStatus.IN_PROGRESS && round.startTimestamp) {
      seconds += Math.floor((currentTime - round.startTimestamp) / 1000);
    }
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const handleStartRound = () => {
    if (!isHost) return;
    const nextRounds = [...event.rounds];
    nextRounds[activeRoundIdx] = {
      ...nextRounds[activeRoundIdx],
      status: RoundStatus.IN_PROGRESS,
      startTimestamp: Date.now()
    };
    onUpdate({ ...event, rounds: nextRounds });
  };

  const handleStopRound = () => {
    if (!isHost) return;
    const round = event.rounds[activeRoundIdx];
    const elapsedSinceStart = round.startTimestamp ? Math.floor((Date.now() - round.startTimestamp) / 1000) : 0;
    const nextRounds = [...event.rounds];
    nextRounds[activeRoundIdx] = {
      ...nextRounds[activeRoundIdx],
      status: RoundStatus.STOPPED,
      elapsedSeconds: round.elapsedSeconds + elapsedSinceStart,
      startTimestamp: undefined
    };
    onUpdate({ ...event, rounds: nextRounds });
  };

  const handleResetRound = () => {
    if (!isHost || !confirm('Reset timer and scores for this round?')) return;
    const nextRounds = [...event.rounds];
    nextRounds[activeRoundIdx] = {
      ...nextRounds[activeRoundIdx],
      status: RoundStatus.NOT_STARTED,
      elapsedSeconds: 0,
      startTimestamp: undefined,
      matches: nextRounds[activeRoundIdx].matches.map(m => ({
        ...m,
        scoreA: 0,
        scoreB: 0,
        status: MatchStatus.PENDING
      }))
    };
    onUpdate({ ...event, rounds: nextRounds });
  };

  const handleScoreChange = (matchId: string, team: 'A' | 'B', val: string) => {
    if (!isHost) return;
    const score = parseInt(val) || 0;
    const nextRounds = [...event.rounds];
    const matchIdx = nextRounds[activeRoundIdx].matches.findIndex(m => m.id === matchId);
    if (matchIdx === -1) return;

    const match = { ...nextRounds[activeRoundIdx].matches[matchIdx] };
    if (team === 'A') match.scoreA = score;
    else match.scoreB = score;

    // Auto-mark complete if scores exist and round is stopped/submitted
    match.status = (match.scoreA > 0 || match.scoreB > 0) ? MatchStatus.COMPLETE : MatchStatus.PENDING;
    match.lastEditedAt = Date.now();

    nextRounds[activeRoundIdx].matches[matchIdx] = match;
    onUpdate({ ...event, rounds: nextRounds });
  };

  const handleSubmitScores = () => {
    if (!isHost) return;
    const nextRounds = [...event.rounds];
    nextRounds[activeRoundIdx] = {
      ...nextRounds[activeRoundIdx],
      status: RoundStatus.SUBMITTED
    };
    onUpdate({ ...event, rounds: nextRounds });
    alert('Scores submitted! Standings updated.');
  };

  if (showStandings) {
    return (
      <div className="max-w-md mx-auto p-4 min-h-screen">
        <header className="flex items-center justify-between mb-8">
          <h1 className="text-3xl font-black text-white">Standings</h1>
          <button onClick={() => setShowStandings(false)} className="p-2 bg-white/20 rounded-full text-white"><ChevronLeft size={24} /></button>
        </header>

        <div className="glass-card rounded-3xl overflow-hidden shadow-2xl">
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-gray-50 text-gray-400 text-[10px] font-bold uppercase tracking-wider">
                  <th className="px-4 py-3">Rank</th>
                  <th className="px-4 py-3">Team</th>
                  <th className="px-2 py-3 text-center">W-L</th>
                  <th className="px-2 py-3 text-center">Diff</th>
                  <th className="px-4 py-3 text-center">Pts</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-100">
                {standings.map(row => (
                  <tr key={row.teamId} className="bg-white">
                    <td className="px-4 py-4 font-black text-[#0984e3]">#{row.rank}</td>
                    <td className="px-4 py-4 font-bold text-gray-800">
                      <div className="truncate w-24 sm:w-32">{row.teamName}</div>
                    </td>
                    <td className="px-2 py-4 text-center font-medium text-gray-600">{row.wins}-{row.losses}</td>
                    <td className="px-2 py-4 text-center font-bold text-green-500">{row.diff > 0 ? '+' : ''}{row.diff}</td>
                    <td className="px-4 py-4 text-center font-black">{row.pointsFor}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col min-h-screen">
      <header className="px-6 pt-6 pb-2">
        <div className="flex items-center justify-between mb-4">
          <div className="flex items-center gap-2">
            <span className="w-3 h-3 rounded-full bg-green-400 animate-pulse shadow-sm shadow-green-200"></span>
            <span className="text-xs font-bold text-white/80 uppercase tracking-widest">Live Event</span>
          </div>
          <div className="flex gap-2">
            <button onClick={() => setShowStandings(true)} className="p-2 bg-white/20 rounded-full text-white"><Trophy size={20} /></button>
            <button className="p-2 bg-white/20 rounded-full text-white"><Settings size={20} /></button>
          </div>
        </div>
        <h1 className="text-2xl font-black text-white truncate">{event.name}</h1>
      </header>

      {/* Round Selector */}
      <div className="flex gap-4 px-6 py-4 overflow-x-auto no-scrollbar mask-gradient">
        {event.rounds.map((r, idx) => (
          <button 
            key={r.id} 
            onClick={() => setActiveRoundIdx(idx)}
            className={`flex-shrink-0 px-5 py-2 rounded-2xl font-bold transition-all ${activeRoundIdx === idx ? 'bg-white text-[#0984e3] shadow-lg' : 'bg-white/10 text-white/60'}`}
          >
            Round {r.roundNumber} {r.status === RoundStatus.SUBMITTED && '✓'}
          </button>
        ))}
      </div>

      <main className="flex-1 px-4 pb-32">
        {/* Round Controls */}
        <div className="glass-card rounded-3xl p-6 mb-6">
          <div className="flex items-center justify-between mb-6">
            <div>
              <div className="text-xs font-bold text-gray-400 uppercase">Elapsed Time</div>
              <div className="text-4xl font-black text-gray-800 tabular-nums">{getTimerDisplay(currentRound)}</div>
            </div>
            <div className="flex gap-2">
              {currentRound.status === RoundStatus.NOT_STARTED || currentRound.status === RoundStatus.STOPPED ? (
                <button onClick={handleStartRound} className="p-4 bg-green-500 rounded-full text-white shadow-lg"><Play size={24} fill="currentColor" /></button>
              ) : currentRound.status === RoundStatus.IN_PROGRESS ? (
                <button onClick={handleStopRound} className="p-4 bg-gray-800 rounded-full text-white shadow-lg"><Square size={24} fill="currentColor" /></button>
              ) : null}
              {isHost && <button onClick={handleResetRound} className="p-4 bg-gray-100 rounded-full text-gray-400"><RotateCcw size={24} /></button>}
            </div>
          </div>

          <div className="space-y-4">
            {currentRound.matches.map(match => {
              const teamA = event.teams.find(t => t.id === match.teamAId);
              const teamB = event.teams.find(t => t.id === match.teamBId);
              return (
                <div key={match.id} className="relative bg-gray-50 border border-gray-100 rounded-2xl p-4 overflow-hidden">
                  <div className="absolute top-0 left-0 bg-[#fdcb6e] text-xs font-black px-2 py-0.5 rounded-br-lg text-white">COURT {match.courtNumber}</div>
                  {match.waveNumber && match.waveNumber > 1 && (
                    <div className="absolute top-0 right-0 bg-blue-100 text-[#0984e3] text-[10px] font-black px-2 py-0.5 rounded-bl-lg">WAVE {match.waveNumber}</div>
                  )}

                  <div className="flex items-center gap-4 mt-2">
                    <div className="flex-1">
                      <div className="font-bold text-gray-800 truncate">{teamA?.name}</div>
                      <div className="text-[10px] text-gray-400 uppercase font-medium">{teamA?.player1} & {teamA?.player2}</div>
                    </div>
                    <input 
                      type="number" 
                      value={match.scoreA || ''} 
                      onChange={e => handleScoreChange(match.id, 'A', e.target.value)}
                      disabled={!isHost || currentRound.status === RoundStatus.SUBMITTED}
                      className="w-14 h-14 bg-white border-2 border-gray-100 rounded-xl text-center text-xl font-black focus:border-[#0984e3] outline-none disabled:bg-gray-50" 
                    />
                    <div className="text-gray-300 font-bold">vs</div>
                    <input 
                      type="number" 
                      value={match.scoreB || ''} 
                      onChange={e => handleScoreChange(match.id, 'B', e.target.value)}
                      disabled={!isHost || currentRound.status === RoundStatus.SUBMITTED}
                      className="w-14 h-14 bg-white border-2 border-gray-100 rounded-xl text-center text-xl font-black focus:border-[#0984e3] outline-none disabled:bg-gray-50" 
                    />
                    <div className="flex-1 text-right">
                      <div className="font-bold text-gray-800 truncate">{teamB?.name}</div>
                      <div className="text-[10px] text-gray-400 uppercase font-medium">{teamB?.player1} & {teamB?.player2}</div>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      </main>

      {isHost && currentRound.status !== RoundStatus.SUBMITTED && (
        <div className="fixed bottom-0 left-0 right-0 p-6 glass-card border-t border-white/20 flex gap-4">
          <Button onClick={handleSubmitScores} className="w-full py-4 text-lg" disabled={currentRound.status === RoundStatus.IN_PROGRESS}>
            Submit Round {currentRound.roundNumber} Scores
          </Button>
        </div>
      )}
    </div>
  );
};

