  className?: string;
  disabled?: boolean;
}> = ({ onClick, children, variant = 'primary', className = '', disabled }) => {
  const baseClasses = "px-6 py-4 font-bold transition-all flex items-center justify-center gap-2 active:invert uppercase tracking-widest text-[11px] sharp-button";
  const variants = {
    primary: "bg-white text-black",
