        <div className="w-full space-y-4">
          <button 
            onClick={copyLink}
            className="w-full flex items-center justify-between p-4 border border-white/20 text-[10px] mono uppercase tracking-widest transition-colors hover:bg-white/5"
          >
            <span className="truncate mr-4 text-white/50">{url}</span>
            {copied ? <Check size={14} className="text-green-400" /> : <Copy size={14} />}
          </button>
          <Button onClick={onClose} variant="primary" className="w-full">CLOSE</Button>
        </div>
      </div>
    </div>
  );
