const Dashboard: React.FC<{ 
  event: Event; 
  onUpdate: (ev: Event) => void;
  isHost: boolean;
}> = ({ event, onUpdate, isHost }) => {
  const [activeRoundIdx, setActiveRoundIdx] = useState(0);
  const [showStandings, setShowStandings] = useState(false);
  const [showQR, setShowQR] = useState(false);
  const [currentTime, setCurrentTime] = useState(Date.now());
  const scrollRef = useRef<HTMLDivElement>(null);

  const currentRound = event.rounds[activeRoundIdx];
  const standings = computeStandings(event);

  // Identify BYE team
  const playingTeamIds = new Set(currentRound.matches.flatMap(m => [m.teamAId, m.teamBId]));
  const byeTeam = event.teams.find(t => !playingTeamIds.has(t.id));

  useEffect(() => {
    const interval = setInterval(() => setCurrentTime(Date.now()), 1000);
    return () => clearInterval(interval);
  }, []);

  const getTimerDisplay = (round: Round) => {
    let seconds = round.elapsedSeconds;
    if (round.status === RoundStatus.IN_PROGRESS && round.startTimestamp) {
      seconds += Math.floor((currentTime - round.startTimestamp) / 1000);
    }
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const handleStartRound = () => {
    if (!isHost) return;
    const nextRounds = [...event.rounds];
    nextRounds[activeRoundIdx] = {
      ...nextRounds[activeRoundIdx],
      status: RoundStatus.IN_PROGRESS,
      startTimestamp: Date.now()
    };
    onUpdate({ ...event, rounds: nextRounds });
  };

  const handleStopRound = () => {
    if (!isHost) return;
    const round = event.rounds[activeRoundIdx];
    const elapsedSinceStart = round.startTimestamp ? Math.floor((Date.now() - round.startTimestamp) / 1000) : 0;
    const nextRounds = [...event.rounds];
    nextRounds[activeRoundIdx] = {
      ...nextRounds[activeRoundIdx],
      status: RoundStatus.STOPPED,
      elapsedSeconds: round.elapsedSeconds + elapsedSinceStart,
      startTimestamp: undefined
    };
    onUpdate({ ...event, rounds: nextRounds });
  };

  const handleResetRound = () => {
    if (!isHost || !confirm('REBOOT ROUND? This wipes scores and timer.')) return;
    const nextRounds = [...event.rounds];
    nextRounds[activeRoundIdx] = {
      ...nextRounds[activeRoundIdx],
      status: RoundStatus.NOT_STARTED,
      elapsedSeconds: 0,
      startTimestamp: undefined,
      matches: nextRounds[activeRoundIdx].matches.map(m => ({
        ...m,
        scoreA: 0,
        scoreB: 0,
        status: MatchStatus.PENDING
      }))
    };
    onUpdate({ ...event, rounds: nextRounds });
  };

  const handleScoreChange = (matchId: string, team: 'A' | 'B', val: string) => {
    if (!isHost) return;
    const score = Math.max(0, parseInt(val) || 0);
    const nextRounds = [...event.rounds];
    const matchIdx = nextRounds[activeRoundIdx].matches.findIndex(m => m.id === matchId);
    if (matchIdx === -1) return;

    const match = { ...nextRounds[activeRoundIdx].matches[matchIdx] };
    if (team === 'A') match.scoreA = score;
    else match.scoreB = score;

    match.status = (match.scoreA > 0 || match.scoreB > 0) ? MatchStatus.COMPLETE : MatchStatus.PENDING;
    match.lastEditedAt = Date.now();

    nextRounds[activeRoundIdx].matches[matchIdx] = match;
    onUpdate({ ...event, rounds: nextRounds });
  };

  const handleSubmitScores = () => {
    if (!isHost) return;
    const nextRounds = [...event.rounds];
    nextRounds[activeRoundIdx] = {
      ...nextRounds[activeRoundIdx],
      status: RoundStatus.SUBMITTED
    };
    onUpdate({ ...event, rounds: nextRounds });
  };

  if (showStandings) {
    return (
      <div className="max-w-md mx-auto p-6 min-h-screen page-transition">
        <header className="flex items-center justify-between mb-12 mt-8">
          <h1 className="text-3xl font-black italic tracking-tighter uppercase">RANKINGS</h1>
          <button onClick={() => setShowStandings(false)} className="p-2 border border-white/20"><X size={20} /></button>
        </header>

        <div className="border border-white/20">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-white/5 text-white/30 text-[9px] font-black uppercase tracking-[0.3em]">
                <th className="px-6 py-4">RK</th>
                <th className="px-6 py-4">OPERATIVES</th>
                <th className="px-6 py-4 text-center">W/L</th>
                <th className="px-6 py-4 text-center">PTS</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-white/10">
              {standings.map(row => {
                const teamData = event.teams.find(t => t.id === row.teamId);
                return (
                  <tr key={row.teamId}>
                    <td className="px-6 py-8 font-black text-sm italic">#{row.rank}</td>
                    <td className="px-6 py-8">
                      <div className="font-bold text-[10px] uppercase tracking-widest leading-relaxed">
                        {teamData?.player1} & {teamData?.player2}
                      </div>
                    </td>
                    <td className="px-6 py-8 text-center text-[10px] mono text-white/50">{row.wins}-{row.losses}</td>
                    <td className="px-6 py-8 text-center font-black text-sm tabular-nums">{row.pointsFor}</td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col min-h-screen page-transition">
      {showQR && <QRModal url={generateEventShareUrl(event)} onClose={() => setShowQR(false)} />}

      <header className="px-6 pt-12 pb-6 border-b border-white/10">
        <div className="flex items-center justify-between mb-8">
          <div className="flex items-center gap-3">
            <span className="text-[9px] font-black text-white/40 uppercase tracking-[0.4em]">Node Active</span>
          </div>
          <div className="flex gap-4">
            <button onClick={() => setShowQR(true)} className="p-3 border border-white/20 active:bg-white active:text-black transition-all"><QrCode size={18} /></button>
            <button onClick={() => setShowStandings(true)} className="p-3 border border-white/20 active:bg-white active:text-black transition-all"><Trophy size={18} /></button>
            <button className="p-3 border border-white/20 active:bg-white active:text-black transition-all"><Settings size={18} /></button>
          </div>
        </div>
        <h1 className="text-4xl font-black italic tracking-tighter uppercase mb-2">{event.name}</h1>
      </header>

      {/* Grid Round Selector */}
      <div className="px-6 py-8">
        <div ref={scrollRef} className="flex gap-3 overflow-x-auto no-scrollbar py-2">
          {event.rounds.map((r, idx) => (
            <button 
              key={r.id} 
              onClick={() => setActiveRoundIdx(idx)}
              className={`flex-shrink-0 w-12 h-12 flex items-center justify-center transition-all border ${
                activeRoundIdx === idx 
                  ? 'bg-white text-black border-white' 
                  : 'bg-transparent text-white/30 border-white/10'
              }`}
            >
              <span className="text-sm font-black italic tabular-nums">{r.roundNumber}</span>
              {r.status === RoundStatus.SUBMITTED && (
                <div className="absolute top-0 right-0 bg-white text-black p-0.5"><Check size={8} strokeWidth={4} /></div>
              )}
            </button>
          ))}
        </div>
      </div>

      <main className="flex-1 px-4 pb-40">
        <div className="px-2 mb-12">
          <div className="flex items-end justify-between mb-2">
             <div className="text-[10px] font-black text-white/30 uppercase tracking-[0.4em]">Elapsed</div>
             <div className="text-[10px] font-black text-white/30 uppercase tracking-[0.4em]">Round {currentRound.roundNumber}</div>
          </div>
          <div className="text-7xl font-black italic tracking-tighter tabular-nums mb-4">{getTimerDisplay(currentRound)}</div>

          {/* BYE DISPLAY */}
          {byeTeam ? (
             <div className="border border-white/20 p-4 flex items-center gap-4 bg-white/[0.03]">
               <div className="bg-white/10 p-2"><RotateCcw size={16} className="text-white/40" /></div>
               <div>
                 <div className="text-[8px] font-black text-white/40 uppercase tracking-[0.3em]">Sitting on Bye</div>
                 <div className="text-[11px] font-black uppercase tracking-widest">{byeTeam.player1} & {byeTeam.player2}</div>
               </div>
             </div>
          ) : (
             <div className="h-[1px] bg-white/20 w-full"></div>
          )}

          {isHost && (
            <div className="flex gap-3 mt-8">
              {currentRound.status === RoundStatus.IN_PROGRESS ? (
                <Button onClick={handleStopRound} variant="primary" className="flex-1">STOP CLOCK</Button>
              ) : (
                <Button onClick={handleStartRound} variant="primary" className="flex-1">START CLOCK</Button>
              )}
              <Button onClick={handleResetRound} variant="ghost" className="px-4">RESET</Button>
            </div>
          )}
        </div>

        <div className="space-y-12">
          {currentRound.matches.map(match => {
            const teamA = event.teams.find(t => t.id === match.teamAId);
            const teamB = event.teams.find(t => t.id === match.teamBId);
            return (
              <div key={match.id} className="page-transition">
                {/* Team Info Row */}
                <div className="flex items-center justify-between px-2 mb-6 border-b border-white/10 pb-4">
                  <div className="flex-1">
                    <div className="text-[10px] font-black uppercase tracking-widest truncate">{teamA?.player1} & {teamA?.player2}</div>
                  </div>
                  <div className="px-4 text-[8px] font-black text-white/20 italic tracking-widest">VS</div>
                  <div className="flex-1 text-right">
                    <div className="text-[10px] font-black uppercase tracking-widest truncate">{teamB?.player1} & {teamB?.player2}</div>
                  </div>
                </div>

                {/* Score Input Row */}
                <div className="flex items-center justify-center gap-4">
                  <input 
                    type="number" 
                    inputMode="numeric"
                    value={match.scoreA || '0'} 
                    onChange={e => handleScoreChange(match.id, 'A', e.target.value)}
                    disabled={!isHost || currentRound.status === RoundStatus.SUBMITTED}
                    className="w-24 h-24 bg-white/5 border border-white/20 text-center text-4xl font-black italic outline-none focus:border-white disabled:opacity-30" 
                  />
                  <div className="text-white/10 text-xs font-black italic uppercase tracking-tighter">SCORE</div>
                  <input 
                    type="number" 
                    inputMode="numeric"
                    value={match.scoreB || '0'} 
                    onChange={e => handleScoreChange(match.id, 'B', e.target.value)}
                    disabled={!isHost || currentRound.status === RoundStatus.SUBMITTED}
                    className="w-24 h-24 bg-white/5 border border-white/20 text-center text-4xl font-black italic outline-none focus:border-white disabled:opacity-30" 
                  />
                </div>

                <div className="mt-4 text-center">
                   <span className="text-[8px] font-black text-white/20 uppercase tracking-[0.5em]">Court {match.courtNumber} {match.waveNumber && match.waveNumber > 1 ? `• Wave ${match.waveNumber}` : ''}</span>
                </div>
              </div>
            );
          })}
        </div>
      </main>

      {isHost && currentRound.status !== RoundStatus.SUBMITTED && (
        <div className="fixed bottom-0 left-0 right-0 p-6 bg-black border-t border-white/10">
          <Button onClick={handleSubmitScores} className="w-full py-6" disabled={currentRound.status === RoundStatus.IN_PROGRESS}>
            Lock Results
          </Button>
        </div>
      )}
    </div>
  );
};

