const Button: React.FC<{
  onClick?: () => void;
  children: React.ReactNode;
  variant?: 'primary' | 'outline' | 'ghost' | 'danger';
  className?: string;
  disabled?: boolean;
}> = ({ onClick, children, variant = 'primary', className = '', disabled }) => {
  const baseClasses = "px-6 py-4 font-bold transition-all flex items-center justify-center gap-2 active:invert uppercase tracking-widest text-[10px] sharp-button shrink-0";
  const variants = {
    primary: "bg-white text-black",
    outline: "bg-transparent text-white border border-white",
    ghost: "bg-transparent text-white/50 border border-white/10",
    danger: "bg-transparent text-red-500 border border-red-500/30 hover:border-red-500"
  };

  return (
    <button onClick={onClick} className={`${baseClasses} ${variants[variant]} ${className}`} disabled={disabled}>
      {children}
    </button>
  );
};

const QRModal: React.FC<{ url: string; onClose: () => void }> = ({ url, onClose }) => {
  const [qrData, setQrData] = useState<string>('');
  const [copied, setCopied] = useState(false);

  useEffect(() => {
    QRCode.toDataURL(url, { 
      width: 400, 
      margin: 1, 
      color: { dark: '#000000', light: '#ffffff' } 
    }).then(setQrData);
  }, [url]);

  const copyLink = () => {
    navigator.clipboard.writeText(url);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/95 animate-in fade-in duration-200">
      <div className="border border-white w-full max-w-sm p-8 flex flex-col items-center text-center bg-black">
        <div className="w-full flex justify-end mb-4">
          <button onClick={onClose} className="p-2 text-white/50 hover:text-white"><X size={24} /></button>
        </div>
        <h2 className="text-xl font-black mb-1 italic tracking-widest uppercase">INVITE ACCESS</h2>
        <p className="text-white/40 text-[10px] mb-8 uppercase tracking-[0.2em]">Real-time observer node</p>

        <div className="bg-white p-2 mb-8">
          {qrData ? <img src={qrData} alt="QR Code" className="w-56 h-56" /> : <div className="w-56 h-56 bg-white/10" />}
        </div>

        <div className="w-full space-y-4">
          <button 
            onClick={copyLink}
            className="w-full flex items-center justify-between p-4 border border-white/20 text-[10px] mono uppercase tracking-widest transition-colors hover:bg-white/5"
          >
            <span className="truncate mr-4 text-white/50 text-left">{url}</span>
            {copied ? <Check size={14} className="text-green-400" /> : <Copy size={14} />}
          </button>
          <Button onClick={onClose} variant="primary" className="w-full">CLOSE</Button>
        </div>
      </div>
    </div>
  );
};

