                className="text-right font-black text-sm outline-none bg-transparent uppercase tracking-widest text-white/50"
              />
            </div>
            <div className="grid grid-cols-1 gap-6">
              <input 
                type="text" placeholder="PLAYER 1" 
                value={team.player1}
                onChange={e => updateTeam(i, 'player1', e.target.value)}
                className="w-full bg-transparent border-b border-white/20 p-4 outline-none text-[11px] font-bold uppercase tracking-[0.3em] focus:border-white"
              />
              <input 
                type="text" placeholder="PLAYER 2" 
                value={team.player2}
                onChange={e => updateTeam(i, 'player2', e.target.value)}
                className="w-full bg-transparent border-b border-white/20 p-4 outline-none text-[11px] font-bold uppercase tracking-[0.3em] focus:border-white"
              />
            </div>
          </div>
        ))}
      </div>

      <div className="fixed bottom-0 left-0 right-0 p-6 bg-black border-t border-white/20">
        <Button onClick={() => onConfirm(teams)} className="w-full py-6" disabled={!isReady}>
          Begin Tournament
        </Button>
      </div>
    </div>
  );
};

const Dashboard: React.FC<{ 
  event: Event; 
  onUpdate: (ev: Event) => void;
  isHost: boolean;
  onResetEvent: () => void;
}> = ({ event, onUpdate, isHost, onResetEvent }) => {
  const [activeRoundIdx, setActiveRoundIdx] = useState(0);
  const [showStandings, setShowStandings] = useState(false);
  const [standingsTab, setStandingsTab] = useState<'RR' | 'PLAYOFFS'>('RR');
  const [showQR, setShowQR] = useState(false);
  const [currentTime, setCurrentTime] = useState(Date.now());
  const scrollRef = useRef<HTMLDivElement>(null);

  const currentRound = event.rounds[activeRoundIdx];
  const standings = useMemo(() => computeStandings(event), [event]);

  // Identify BYE team
  const playingTeamIds = new Set(currentRound?.matches.flatMap(m => [m.teamAId, m.teamBId]) || []);
  const byeTeam = event.teams.find(t => !playingTeamIds.has(t.id));

  useEffect(() => {
    const interval = setInterval(() => setCurrentTime(Date.now()), 1000);
    return () => clearInterval(interval);
  }, []);

  const getTimerDisplay = (round: Round) => {
    if (!round) return "00:00";
    let seconds = round.elapsedSeconds;
    if (round.status === RoundStatus.IN_PROGRESS && round.startTimestamp) {
      seconds += Math.floor((currentTime - round.startTimestamp) / 1000);
    }
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const handleStartRound = () => {
    if (!isHost) return;
    const nextRounds = [...event.rounds];
    nextRounds[activeRoundIdx] = {
      ...nextRounds[activeRoundIdx],
      status: RoundStatus.IN_PROGRESS,
      startTimestamp: Date.now()
    };
    onUpdate({ ...event, rounds: nextRounds });
  };

  const handleStopRound = () => {
    if (!isHost) return;
    const round = event.rounds[activeRoundIdx];
    const elapsedSinceStart = round.startTimestamp ? Math.floor((Date.now() - round.startTimestamp) / 1000) : 0;
    const nextRounds = [...event.rounds];
    nextRounds[activeRoundIdx] = {
      ...nextRounds[activeRoundIdx],
      status: RoundStatus.STOPPED,
      elapsedSeconds: round.elapsedSeconds + elapsedSinceStart,
      startTimestamp: undefined
    };
    onUpdate({ ...event, rounds: nextRounds });
  };

  const handleResetRound = () => {
    if (!isHost || !confirm('REBOOT ROUND? This wipes scores and timer.')) return;
    const nextRounds = [...event.rounds];
    nextRounds[activeRoundIdx] = {
      ...nextRounds[activeRoundIdx],
      status: RoundStatus.NOT_STARTED,
      elapsedSeconds: 0,
      startTimestamp: undefined,
      matches: nextRounds[activeRoundIdx].matches.map(m => ({
        ...m,
        scoreA: 0,
        scoreB: 0,
        status: MatchStatus.PENDING
      }))
    };
    onUpdate({ ...event, rounds: nextRounds });
  };

  const handleScoreChange = (matchId: string, team: 'A' | 'B', val: string) => {
    if (!isHost) return;
    const score = Math.max(0, parseInt(val) || 0);
    const nextRounds = [...event.rounds];
    const matchIdx = nextRounds[activeRoundIdx].matches.findIndex(m => m.id === matchId);
    if (matchIdx === -1) return;

    const match = { ...nextRounds[activeRoundIdx].matches[matchIdx] };
    if (team === 'A') match.scoreA = score;
    else match.scoreB = score;

    match.status = (match.scoreA > 0 || match.scoreB > 0) ? MatchStatus.COMPLETE : MatchStatus.PENDING;
    match.lastEditedAt = Date.now();

    nextRounds[activeRoundIdx].matches[matchIdx] = match;
    onUpdate({ ...event, rounds: nextRounds });
  };

  const handleSubmitScores = () => {
    if (!isHost) return;
    const nextRounds = [...event.rounds];
    nextRounds[activeRoundIdx] = {
      ...nextRounds[activeRoundIdx],
      status: RoundStatus.SUBMITTED
    };
    onUpdate({ ...event, rounds: nextRounds });
  };

  const createPlayoffs = () => {
    if (!isHost || event.playoffRounds) return;
    const top4 = standings.slice(0, 4);
    if (top4.length < 2) return alert("Not enough teams for playoffs.");

    // Simple Bracket: 1v4, 2v3
    const semiFinals: Round = {
      id: 'playoff-semis',
      roundNumber: 'SF',
      status: RoundStatus.NOT_STARTED,
      elapsedSeconds: 0,
      matches: [
        {
          id: 'sf-1',
          courtNumber: 1,
          teamAId: top4[0].teamId,
          teamBId: top4[3]?.teamId || 'BYE',
          scoreA: 0,
          scoreB: 0,
          status: MatchStatus.PENDING,
          isPlayoff: true
        },
        {
          id: 'sf-2',
          courtNumber: 2,
          teamAId: top4[1].teamId,
          teamBId: top4[2].teamId,
          scoreA: 0,
          scoreB: 0,
          status: MatchStatus.PENDING,
          isPlayoff: true
        }
      ]
    };

    onUpdate({ ...event, playoffRounds: [semiFinals] });
    setStandingsTab('PLAYOFFS');
  };

  const isAllRRSubmitted = event.rounds.every(r => r.status === RoundStatus.SUBMITTED);

  if (showStandings) {
    return (
      <div className="max-w-md mx-auto p-6 min-h-screen page-transition">
        <header className="flex items-center justify-between mb-8 mt-4">
          <h1 className="text-2xl font-black italic tracking-tighter uppercase">RANKINGS</h1>
          <button onClick={() => setShowStandings(false)} className="p-2 border border-white/20"><X size={20} /></button>
        </header>

        <div className="flex border border-white/10 mb-8">
          <button 
            onClick={() => setStandingsTab('RR')}
            className={`flex-1 py-3 text-[10px] font-black tracking-widest uppercase ${standingsTab === 'RR' ? 'bg-white text-black' : 'text-white/40'}`}
          >
            Round Robin
          </button>
          <button 
            onClick={() => setStandingsTab('PLAYOFFS')}
            className={`flex-1 py-3 text-[10px] font-black tracking-widest uppercase ${standingsTab === 'PLAYOFFS' ? 'bg-white text-black' : 'text-white/40'}`}
          >
            Playoffs
          </button>
        </div>

        {standingsTab === 'RR' ? (
          <div className="border border-white/20">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-white/5 text-white/30 text-[9px] font-black uppercase tracking-[0.3em]">
                  <th className="px-4 py-3">RK</th>
                  <th className="px-4 py-3">SQUAD</th>
                  <th className="px-4 py-3 text-center">W/L</th>
                  <th className="px-4 py-3 text-center">PTS</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-white/10">
                {standings.map(row => {
                  const teamData = event.teams.find(t => t.id === row.teamId);
                  return (
                    <tr key={row.teamId}>
                      <td className="px-4 py-6 font-black text-sm italic">#{row.rank}</td>
                      <td className="px-4 py-6">
                        <div className="font-bold text-[9px] uppercase tracking-widest leading-relaxed">
                          {teamData?.player1} & {teamData?.player2}
                        </div>
                      </td>
                      <td className="px-4 py-6 text-center text-[9px] mono text-white/50">{row.wins}-{row.losses}</td>
                      <td className="px-4 py-6 text-center font-black text-sm tabular-nums">{row.pointsFor}</td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        ) : (
          <div className="space-y-8">
            {!event.playoffRounds && isAllRRSubmitted && isHost ? (
               <div className="text-center p-8 border border-dashed border-white/20">
                 <p className="text-[10px] text-white/40 uppercase tracking-widest mb-6">Round Robin sequence complete.</p>
                 <Button onClick={createPlayoffs} className="w-full">Initialize Playoffs (Top 4)</Button>
               </div>
            ) : !event.playoffRounds ? (
               <div className="text-center p-12 text-white/20 text-[10px] uppercase tracking-widest">
                 Playoffs lock until RR complete.
               </div>
            ) : (
              <div className="space-y-6">
                {event.playoffRounds.map(rnd => (
                  <div key={rnd.id} className="border border-white/20 p-4">
                    <h3 className="text-[10px] font-black tracking-[0.3em] uppercase mb-6 text-white/40">{rnd.roundNumber} Matches</h3>
                    <div className="space-y-6">
                      {rnd.matches.map(m => {
                        const tA = event.teams.find(t => t.id === m.teamAId);
                        const tB = event.teams.find(t => t.id === m.teamBId);
                        return (
                          <div key={m.id} className="flex items-center justify-between border-b border-white/10 pb-4">
                            <div className="text-left w-1/3">
                              <div className="text-[9px] font-bold uppercase truncate">{tA?.player1 || "—"}</div>
                              <div className="text-[9px] font-bold uppercase truncate">{tA?.player2 || "—"}</div>
                            </div>
                            <div className="flex items-center gap-2">
                              <span className="mono text-lg font-black">{m.scoreA}</span>
                              <span className="text-[8px] text-white/20">VS</span>
                              <span className="mono text-lg font-black">{m.scoreB}</span>
                            </div>
                            <div className="text-right w-1/3">
                              <div className="text-[9px] font-bold uppercase truncate">{tB?.player1 || "—"}</div>
                              <div className="text-[9px] font-bold uppercase truncate">{tB?.player2 || "—"}</div>
                            </div>
                          </div>
                        )
                      })}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}
      </div>
    );
  }

  return (
    <div className="flex flex-col h-screen overflow-hidden page-transition">
      {showQR && <QRModal url={generateEventShareUrl(event)} onClose={() => setShowQR(false)} />}

      {/* COMPACT HEADER */}
      <header className="px-6 py-4 border-b border-white/10 flex items-center justify-between">
        <div className="flex flex-col">
          <h1 className="text-sm font-black italic tracking-tighter uppercase text-white/80">{event.name}</h1>
          <div className="flex items-center gap-2">
            <span className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></span>
            <span className="text-[8px] font-bold text-white/30 uppercase tracking-widest">Live Node</span>
          </div>
        </div>
        <div className="flex gap-2">
          <button onClick={() => setShowQR(true)} className="p-2 border border-white/10 hover:bg-white active:text-black transition-all"><QrCode size={14} /></button>
          <button onClick={() => setShowStandings(true)} className="p-2 border border-white/10 hover:bg-white active:text-black transition-all"><Trophy size={14} /></button>
          <button onClick={onResetEvent} className="p-2 border border-red-500/30 text-red-500 hover:bg-red-500 hover:text-white transition-all"><Home size={14} /></button>
        </div>
      </header>

      {/* DASHBOARD CONTENT */}
      <main className="flex-1 overflow-y-auto px-4 pt-6 pb-24 no-scrollbar">
        {/* COMPACT TIMER SECTION */}
        <div className="px-2 mb-8">
          <div className="flex items-center justify-between mb-1">
             <div className="text-[8px] font-black text-white/20 uppercase tracking-[0.4em]">Chronometer</div>
             <div className="text-[8px] font-black text-white/20 uppercase tracking-[0.4em]">Rnd {currentRound?.roundNumber}</div>
          </div>
          <div className="flex items-baseline justify-between mb-4">
             <div className="text-5xl font-black italic tracking-tighter tabular-nums">{getTimerDisplay(currentRound)}</div>
             {isHost && (
              <div className="flex gap-2">
                <button onClick={currentRound?.status === RoundStatus.IN_PROGRESS ? handleStopRound : handleStartRound} className="p-3 border border-white/20">
                  {currentRound?.status === RoundStatus.IN_PROGRESS ? <Square size={14} fill="white" /> : <Play size={14} fill="white" />}
                </button>
                <button onClick={handleResetRound} className="p-3 border border-white/20"><RotateCcw size={14} /></button>
              </div>
             )}
          </div>

          {/* COMPACT BYE DISPLAY */}
          {byeTeam && (
             <div className="border border-white/10 p-2 flex items-center justify-between bg-white/[0.02]">
                <div className="text-[8px] font-black text-white/30 uppercase tracking-widest">Round Bye</div>
                <div className="text-[9px] font-black uppercase tracking-widest truncate max-w-[150px]">{byeTeam.player1} & {byeTeam.player2}</div>
             </div>
          )}
        </div>

        {/* MATCHES LIST */}
        <div className="space-y-12">
          {currentRound?.matches.map(match => {
            const teamA = event.teams.find(t => t.id === match.teamAId);
            const teamB = event.teams.find(t => t.id === match.teamBId);
            return (
              <div key={match.id} className="page-transition">
                {/* Team Info Row: Top-aligned and compact */}
                <div className="flex items-start justify-between px-2 mb-4 border-b border-white/10 pb-3">
                  <div className="flex-1">
                    <div className="text-[9px] font-black uppercase tracking-wider leading-tight">{teamA?.player1}</div>
                    <div className="text-[9px] font-black uppercase tracking-wider leading-tight">& {teamA?.player2}</div>
                  </div>
                  <div className="px-3 text-[7px] font-black text-white/20 italic tracking-widest self-center">VS</div>
                  <div className="flex-1 text-right">
                    <div className="text-[9px] font-black uppercase tracking-wider leading-tight">{teamB?.player1}</div>
                    <div className="text-[9px] font-black uppercase tracking-wider leading-tight">& {teamB?.player2}</div>
                  </div>
                </div>

                {/* Score Input Row: Large for visibility but aligned centrally */}
                <div className="flex items-center justify-center gap-6">
                  <input 
                    type="number" 
                    inputMode="numeric"
                    value={match.scoreA || '0'} 
                    onChange={e => handleScoreChange(match.id, 'A', e.target.value)}
                    disabled={!isHost || currentRound.status === RoundStatus.SUBMITTED}
                    className="w-20 h-20 bg-white/5 border border-white/10 text-center text-3xl font-black italic outline-none focus:border-white disabled:opacity-20" 
                  />
                  <div className="flex flex-col items-center">
                    <div className="text-white/10 text-[7px] font-black italic uppercase tracking-[0.5em] mb-1">SCORE</div>
                    <div className="text-[7px] font-black text-white/20 tracking-widest uppercase">CRT {match.courtNumber}</div>
                  </div>
                  <input 
                    type="number" 
                    inputMode="numeric"
                    value={match.scoreB || '0'} 
                    onChange={e => handleScoreChange(match.id, 'B', e.target.value)}
                    disabled={!isHost || currentRound.status === RoundStatus.SUBMITTED}
                    className="w-20 h-20 bg-white/5 border border-white/10 text-center text-3xl font-black italic outline-none focus:border-white disabled:opacity-20" 
                  />
                </div>
              </div>
            );
          })}
        </div>
      </main>

      {/* FOOTER: LOCK BUTTON + ROUND SELECTOR */}
      <footer className="fixed bottom-0 left-0 right-0 bg-black border-t border-white/10 z-40">
        {isHost && currentRound?.status !== RoundStatus.SUBMITTED && (
           <button 
             onClick={handleSubmitScores}
             disabled={currentRound?.status === RoundStatus.IN_PROGRESS}
             className="w-full py-4 text-[10px] font-black uppercase tracking-[0.4em] bg-white text-black active:invert disabled:opacity-50"
           >
             Lock Round {currentRound?.roundNumber}
           </button>
        )}

        {/* ROUND SLIDER */}
        <div className="px-6 py-4 flex gap-2 overflow-x-auto no-scrollbar scroll-smooth">
          {event.rounds.map((r, idx) => (
            <button 
              key={r.id} 
              onClick={() => setActiveRoundIdx(idx)}
              className={`flex-shrink-0 w-10 h-10 flex items-center justify-center transition-all border ${
                activeRoundIdx === idx 
                  ? 'bg-white text-black border-white' 
                  : 'bg-transparent text-white/30 border-white/10'
              }`}
            >
              <span className="text-[10px] font-black italic tabular-nums">{r.roundNumber}</span>
              {r.status === RoundStatus.SUBMITTED && (
                <div className="absolute top-0 right-0 bg-white text-black p-0.5"><Check size={6} strokeWidth={4} /></div>
              )}
            </button>
          ))}
        </div>
      </footer>
    </div>
  );
};

