export default function App() {
  const [view, setView] = useState<'LANDING' | 'CREATE' | 'TEAM_SETUP' | 'DASHBOARD'>('LANDING');
  const [activeEvent, setActiveEvent] = useState<Event | null>(null);

  useEffect(() => {
    const handleHash = () => {
      const hash = window.location.hash;
      if (hash.startsWith('#/event/')) {
        const id = hash.replace('#/event/', '');
        const ev = getEvent(id);
        if (ev) {
          setActiveEvent(ev);
          setView('DASHBOARD');
        }
      } else {
        setView('LANDING');
      }
    };
    window.addEventListener('hashchange', handleHash);
    handleHash();
    return () => window.removeEventListener('hashchange', handleHash);
  }, []);

  const handleCreateNew = () => setView('CREATE');

  const handleEventCreated = (ev: Event) => {
    setActiveEvent(ev);
    setView('TEAM_SETUP');
  };

  const handleTeamsConfirmed = (teams: Team[]) => {
    if (!activeEvent) return;
    const rounds = generateSchedule(teams, activeEvent.numberOfCourts);
    const updated = { ...activeEvent, teams, rounds };
    setActiveEvent(updated);
    saveEvent(updated);
    window.location.hash = `#/event/${updated.id}`;
    setView('DASHBOARD');
  };

  const handleEventUpdate = (updated: Event) => {
    setActiveEvent(updated);
    saveEvent(updated);
  };

  const handleResetEverything = () => {
    if (confirm("Are you sure you want to reset the event? This will remove everything and take you back to the home screen")) {
      window.location.hash = '';
      setView('LANDING');
      setActiveEvent(null);
    }
  };

  const isHost = activeEvent ? getHostToken(activeEvent.id) === activeEvent.hostToken : false;

  return (
    <div className="min-h-screen relative text-white selection:bg-white selection:text-black bg-black">
      <NagaiBackground />
      <div className="relative z-10">
        {view === 'LANDING' && <LandingView onCreate={handleCreateNew} onResume={(id) => window.location.hash = `#/event/${id}`} />}
        {view === 'CREATE' && <CreateView onCreated={handleEventCreated} onBack={() => setView('LANDING')} />}
        {view === 'TEAM_SETUP' && activeEvent && <TeamSetupView event={activeEvent} onConfirm={handleTeamsConfirmed} />}
        {view === 'DASHBOARD' && activeEvent && (
          <Dashboard 
            event={activeEvent} 
            onUpdate={handleEventUpdate} 
            isHost={isHost}
            onResetEvent={handleResetEverything}
          />
        )}
      </div>
    </div>
  );
}

export type ScoringType = 'TRADITIONAL' | 'POINTS_FOR' | 'WIN_DIFF';

export interface Player {
  name: string;
}

export interface Team {
  id: string;
  name: string;
  player1: string;
  player2: string;
}

export enum MatchStatus {
  PENDING = 'pending',
  COMPLETE = 'complete'
}

export interface Match {
  id: string;
  courtNumber: number;
  waveNumber?: number;
  teamAId: string;
  teamBId: string; // "BYE" if odd teams
  scoreA: number | null;
  scoreB: number | null;
  status: MatchStatus;
  winnerId?: string;
  submittedAt?: number;
  lastEditedAt?: number;
  isPlayoff?: boolean;
}

export enum RoundStatus {
  NOT_STARTED = 'not_started',
  IN_PROGRESS = 'in_progress',
  STOPPED = 'stopped',
  SUBMITTED = 'submitted'
}

export interface Round {
  id: string;
  roundNumber: number | string; // e.g., 1, 2 or "Semi-Final"
  status: RoundStatus;
  startTimestamp?: number;
  elapsedSeconds: number;
  matches: Match[];
}

export interface Event {
  id: string;
  name: string;
  createdAt: number;
  hostToken: string;
  hostPasscode: string;
  numberOfTeams: number;
  numberOfCourts: number;
  pointsPerGame: number;
  winBy2: boolean;
  scoringType: ScoringType;
  teams: Team[];
  rounds: Round[];
  playoffRounds?: Round[];
}

export interface StandingRow {
  rank: number;
  teamId: string;
  teamName: string;
  wins: number;
  losses: number;
  pointsFor: number;
  pointsAgainst: number;
  diff: number;
  gamesPlayed: number;
  byeCount: number;
}

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { 
  Plus, 
  Share2, 
  Trophy, 
  ChevronRight, 
  ChevronLeft, 
  Play, 
  Pause, 
  RotateCcw, 
  QrCode, 
  X, 
  Copy, 
  Check, 
  Home,
  Crown
} from 'lucide-react';
import { nanoid } from 'nanoid';
import QRCode from 'qrcode';
import { Event, Team, Round, Match, RoundStatus, MatchStatus, StandingRow } from './types';
