// --- Components ---

const Button: React.FC<{
  onClick?: () => void;
  children: React.ReactNode;
  variant?: 'primary' | 'outline' | 'ghost' | 'danger';
  className?: string;
  disabled?: boolean;
}> = ({ onClick, children, variant = 'primary', className = '', disabled }) => {
  const baseClasses = "px-4 py-3 font-bold transition-all flex items-center justify-center gap-2 active:invert uppercase tracking-widest text-[10px] sharp-button shrink-0";
  const variants = {
    primary: "bg-white text-black border border-white",
    outline: "bg-transparent text-white border border-white",
    ghost: "bg-transparent text-white/50 border border-white/10",
    danger: "bg-transparent text-red-500 border border-red-500/30 hover:border-red-500"
  };

  return (
    <button onClick={onClick} className={`${baseClasses} ${variants[variant]} ${className}`} disabled={disabled}>
      {children}
    </button>
  );
};

const QRModal: React.FC<{ url: string; onClose: () => void }> = ({ url, onClose }) => {
  const [qrData, setQrData] = useState<string>('');
  const [copied, setCopied] = useState(false);

  useEffect(() => {
    QRCode.toDataURL(url, { 
      width: 400, 
      margin: 1, 
      color: { dark: '#000000', light: '#ffffff' } 
    }).then(setQrData);
  }, [url]);

  const copyLink = () => {
    navigator.clipboard.writeText(url);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/95 animate-in fade-in duration-200">
      <div className="border border-white w-full max-w-sm p-6 flex flex-col items-center text-center bg-black">
        <div className="w-full flex justify-end mb-4">
