const Dashboard: React.FC<{ 
  event: Event; 
  onUpdate: (ev: Event) => void;
  isHost: boolean;
  onResetEvent: () => void;
}> = ({ event, onUpdate, isHost, onResetEvent }) => {
  const [activeRoundIdx, setActiveRoundIdx] = useState(0);
  const [showStandings, setShowStandings] = useState(false);
  const [standingsTab, setStandingsTab] = useState<'RR' | 'PLAYOFFS'>('RR');
  const [showQR, setShowQR] = useState(false);
  const [currentTime, setCurrentTime] = useState(Date.now());
  const scrollRef = useRef<HTMLDivElement>(null);

  const currentRound = event.rounds[activeRoundIdx];
  const standings = useMemo(() => computeStandings(event), [event]);

  // Identify BYE team
  const playingTeamIds = new Set(currentRound?.matches.flatMap(m => [m.teamAId, m.teamBId]) || []);
  const byeTeam = event.teams.find(t => !playingTeamIds.has(t.id));

  useEffect(() => {
    const interval = setInterval(() => setCurrentTime(Date.now()), 1000);
    return () => clearInterval(interval);
  }, []);

  const getTimerDisplay = (round: Round) => {
    if (!round) return "00:00";
    let seconds = round.elapsedSeconds;
    if (round.status === RoundStatus.IN_PROGRESS && round.startTimestamp) {
      seconds += Math.floor((currentTime - round.startTimestamp) / 1000);
    }
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const handleStartRound = () => {
    if (!isHost) return;
    const nextRounds = [...event.rounds];
    nextRounds[activeRoundIdx] = {
      ...nextRounds[activeRoundIdx],
      status: RoundStatus.IN_PROGRESS,
      startTimestamp: Date.now()
    };
    onUpdate({ ...event, rounds: nextRounds });
  };

  const handleStopRound = () => {
    if (!isHost) return;
    const round = event.rounds[activeRoundIdx];
    const elapsedSinceStart = round.startTimestamp ? Math.floor((Date.now() - round.startTimestamp) / 1000) : 0;
    const nextRounds = [...event.rounds];
    nextRounds[activeRoundIdx] = {
      ...nextRounds[activeRoundIdx],
      status: RoundStatus.STOPPED,
      elapsedSeconds: round.elapsedSeconds + elapsedSinceStart,
      startTimestamp: undefined
    };
    onUpdate({ ...event, rounds: nextRounds });
  };

  const handleResetRound = () => {
    if (!isHost || !confirm('REBOOT ROUND? This wipes ALL scores and timer for this round.')) return;
    const nextRounds = [...event.rounds];
    nextRounds[activeRoundIdx] = {
      ...nextRounds[activeRoundIdx],
      status: RoundStatus.NOT_STARTED,
      elapsedSeconds: 0,
      startTimestamp: undefined,
      matches: nextRounds[activeRoundIdx].matches.map(m => ({
        ...m,
        scoreA: null,
        scoreB: null,
        winnerId: undefined,
        status: MatchStatus.PENDING
      }))
    };
    onUpdate({ ...event, rounds: nextRounds });
  };

  const handleWinnerSelect = (matchId: string, teamId: string) => {
    if (!isHost || currentRound.status === RoundStatus.SUBMITTED) return;
    const nextRounds = [...event.rounds];
    const matchIdx = nextRounds[activeRoundIdx].matches.findIndex(m => m.id === matchId);
    if (matchIdx === -1) return;

    const match = { ...nextRounds[activeRoundIdx].matches[matchIdx] };
    match.winnerId = teamId;
    nextRounds[activeRoundIdx].matches[matchIdx] = match;
    onUpdate({ ...event, rounds: nextRounds });
  };

  const handleScoreChange = (matchId: string, team: 'A' | 'B', val: string) => {
    if (!isHost) return;
    const cleanVal = val.replace(/[^0-9]/g, '').slice(0, 2);
    const score = cleanVal === '' ? null : parseInt(cleanVal);

    const nextRounds = [...event.rounds];
    const matchIdx = nextRounds[activeRoundIdx].matches.findIndex(m => m.id === matchId);
    if (matchIdx === -1) return;

    const match = { ...nextRounds[activeRoundIdx].matches[matchIdx] };

    // Check if winner is selected
    if (!match.winnerId) {
      alert("Please select a winner first.");
      return;
    }

    if (team === 'A') match.scoreA = score;
    else match.scoreB = score;

    match.status = (match.scoreA !== null || match.scoreB !== null) ? MatchStatus.COMPLETE : MatchStatus.PENDING;
    match.lastEditedAt = Date.now();

    nextRounds[activeRoundIdx].matches[matchIdx] = match;
    onUpdate({ ...event, rounds: nextRounds });
  };

  const handleSubmitScores = () => {
    if (!isHost) return;
    const nextRounds = [...event.rounds];
    nextRounds[activeRoundIdx] = {
      ...nextRounds[activeRoundIdx],
      status: RoundStatus.SUBMITTED
    };
    onUpdate({ ...event, rounds: nextRounds });
  };

  const createPlayoffs = () => {
    if (!isHost || event.playoffRounds) return;
    const top4 = standings.slice(0, 4);
    if (top4.length < 2) return alert("Not enough teams for playoffs.");

    const semiFinals: Round = {
      id: 'playoff-semis',
      roundNumber: 'SF',
      status: RoundStatus.NOT_STARTED,
      elapsedSeconds: 0,
      matches: [
        {
          id: 'sf-1',
          courtNumber: 1,
          teamAId: top4[0].teamId,
          teamBId: top4[3]?.teamId || 'BYE',
          scoreA: null,
          scoreB: null,
          status: MatchStatus.PENDING,
          isPlayoff: true
        },
        {
          id: 'sf-2',
          courtNumber: 2,
          teamAId: top4[1].teamId,
          teamBId: top4[2].teamId,
          scoreA: null,
          scoreB: null,
          status: MatchStatus.PENDING,
          isPlayoff: true
        }
      ]
    };

    onUpdate({ ...event, playoffRounds: [semiFinals] });
    setStandingsTab('PLAYOFFS');
  };

  const shareStandings = () => {
    if (navigator.share) {
      navigator.share({
        title: `${event.name} Standings`,
        text: `Check out the live standings for ${event.name}!`,
        url: window.location.href
      });
    }
  };

  const isAllRRSubmitted = event.rounds.every(r => r.status === RoundStatus.SUBMITTED);

  if (showStandings) {
    return (
      <div className="max-w-md mx-auto p-6 min-h-screen page-transition">
        <header className="flex items-center justify-between mb-8 mt-4">
          <h1 className="text-2xl font-black italic tracking-tighter uppercase">RANKINGS</h1>
          <div className="flex gap-2">
            <button onClick={shareStandings} className="p-2 border border-white/20"><Share2 size={18} /></button>
            <button onClick={() => setShowStandings(false)} className="p-2 border border-white/20"><X size={20} /></button>
          </div>
        </header>

        <div className="flex border border-white/10 mb-8">
          <button 
            onClick={() => setStandingsTab('RR')}
            className={`flex-1 py-3 text-[9px] font-black tracking-widest uppercase ${standingsTab === 'RR' ? 'bg-white text-black' : 'text-white/40'}`}
          >
            Round Robin
          </button>
          <button 
            onClick={() => setStandingsTab('PLAYOFFS')}
            className={`flex-1 py-3 text-[9px] font-black tracking-widest uppercase ${standingsTab === 'PLAYOFFS' ? 'bg-white text-black' : 'text-white/40'}`}
          >
            Playoffs
          </button>
        </div>

        {standingsTab === 'RR' ? (
          <div className="border border-white/20">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-white/5 text-white/30 text-[8px] font-black uppercase tracking-[0.3em]">
                  <th className="px-4 py-3">RK</th>
                  <th className="px-4 py-3">SQUAD</th>
                  <th className="px-4 py-3 text-center">W/L</th>
                  <th className="px-4 py-3 text-center">PTS</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-white/10">
                {standings.map(row => {
                  const teamData = event.teams.find(t => t.id === row.teamId);
                  return (
                    <tr key={row.teamId}>
                      <td className="px-4 py-6 font-black text-xs italic">#{row.rank}</td>
                      <td className="px-4 py-6">
                        <div className="font-bold text-[8px] uppercase tracking-widest leading-relaxed">
                          {teamData?.player1} & {teamData?.player2}
                        </div>
                      </td>
                      <td className="px-4 py-6 text-center text-[8px] mono text-white/50">{row.wins}-{row.losses}</td>
                      <td className="px-4 py-6 text-center font-black text-xs tabular-nums">{row.pointsFor}</td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        ) : (
          <div className="space-y-6">
            {!event.playoffRounds && isAllRRSubmitted && isHost ? (
               <div className="text-center p-6 border border-dashed border-white/20">
                 <p className="text-[9px] text-white/40 uppercase tracking-widest mb-4">Round Robin Complete.</p>
                 <Button onClick={createPlayoffs} className="w-full">Initialize Playoffs</Button>
               </div>
            ) : !event.playoffRounds ? (
               <div className="text-center p-12 text-white/20 text-[9px] uppercase tracking-widest">
                 Playoffs available after RR.
               </div>
            ) : (
              <div className="space-y-4">
                {event.playoffRounds.map(rnd => (
                  <div key={rnd.id} className="border border-white/20 p-4">
                    <h3 className="text-[9px] font-black tracking-[0.3em] uppercase mb-4 text-white/40">{rnd.roundNumber}</h3>
                    <div className="space-y-4">
                      {rnd.matches.map(m => {
                        const tA = event.teams.find(t => t.id === m.teamAId);
                        const tB = event.teams.find(t => t.id === m.teamBId);
                        return (
                          <div key={m.id} className="flex items-center justify-between border-b border-white/10 pb-3">
                            <div className="text-left w-1/3">
                              <div className="text-[8px] font-bold uppercase truncate">{tA?.player1 || "—"}</div>
                              <div className="text-[8px] font-bold uppercase truncate">{tA?.player2 || "—"}</div>
                            </div>
                            <div className="flex items-center gap-2">
                              <span className="mono text-base font-black">{m.scoreA ?? 0}</span>
                              <span className="text-[7px] text-white/20">VS</span>
                              <span className="mono text-base font-black">{m.scoreB ?? 0}</span>
                            </div>
                            <div className="text-right w-1/3">
                              <div className="text-[8px] font-bold uppercase truncate">{tB?.player1 || "—"}</div>
                              <div className="text-[8px] font-bold uppercase truncate">{tB?.player2 || "—"}</div>
                            </div>
                          </div>
                        )
                      })}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}
      </div>
    );
  }

  return (
    <div className="flex flex-col h-screen overflow-hidden page-transition">
      {showQR && <QRModal url={generateEventShareUrl(event)} onClose={() => setShowQR(false)} />}

      {/* HEADER: Reset Event focused */}
      <header className="px-6 py-3 border-b border-white/10 flex items-center justify-between bg-black">
        <div className="flex flex-col">
          <h1 className="text-[10px] font-black italic tracking-tighter uppercase text-white/80">{event.name}</h1>
          <div className="flex items-center gap-1.5">
            <span className="w-1 h-1 bg-green-500 rounded-full animate-pulse"></span>
            <span className="text-[7px] font-bold text-white/30 uppercase tracking-widest">Live Node</span>
          </div>
        </div>
        <div className="flex gap-2">
          <button onClick={() => setShowQR(true)} className="p-2 border border-white/10 active:bg-white active:text-black"><QrCode size={12} /></button>
          <button onClick={() => setShowStandings(true)} className="p-2 border border-white/10 active:bg-white active:text-black"><Trophy size={12} /></button>
          <button 
            onClick={onResetEvent} 
            className="px-3 py-1.5 border border-red-500/30 text-red-500 text-[8px] font-black uppercase tracking-widest hover:bg-red-500 hover:text-white"
          >
            RESET EVENT
          </button>
        </div>
      </header>

      {/* MAIN CONTENT: Balanced spacing */}
      <main className="flex-1 overflow-y-auto px-4 pt-4 pb-48 no-scrollbar">
        {/* TIMER SECTION */}
        <div className="px-2 mb-6">
          <div className="flex items-center justify-between mb-1">
             <div className="text-[7px] font-black text-white/20 uppercase tracking-[0.4em]">Chronometer</div>
             <div className="text-[7px] font-black text-white/20 uppercase tracking-[0.4em]">Round {currentRound?.roundNumber}</div>
          </div>
          <div className="flex items-center justify-between mb-4">
             <div className="text-4xl font-black italic tracking-tighter tabular-nums">{getTimerDisplay(currentRound)}</div>
             {isHost && (
              <div className="flex gap-1.5">
                <button 
                  onClick={currentRound?.status === RoundStatus.IN_PROGRESS ? handleStopRound : handleStartRound} 
                  className="p-3 border border-white/20 flex items-center justify-center min-w-[40px]"
                >
                  {currentRound?.status === RoundStatus.IN_PROGRESS ? <Pause size={14} fill="white" /> : <Play size={14} fill="white" />}
                </button>
                <button 
                  onClick={handleResetRound} 
                  className="p-3 border border-white/20 flex items-center justify-center min-w-[40px]"
                  title="Reset Round"
                >
                  <RotateCcw size={14} />
                </button>
              </div>
             )}
          </div>

          {byeTeam && (
             <div className="border border-white/10 p-2 flex items-center justify-between bg-white/[0.02] border-dashed">
                <div className="text-[7px] font-black text-white/30 uppercase tracking-widest">Sitting Bye</div>
                <div className="text-[8px] font-black uppercase tracking-widest truncate">{byeTeam.player1} & {byeTeam.player2}</div>
             </div>
          )}
        </div>

        {/* MATCHES LIST: Non-overlapping, clear workflow */}
        <div className="space-y-10">
          {currentRound?.matches.map(match => {
            const teamA = event.teams.find(t => t.id === match.teamAId);
            const teamB = event.teams.find(t => t.id === match.teamBId);
            return (
              <div key={match.id} className="page-transition">
                {/* Winner Select Row */}
                <div className="flex items-center justify-between px-2 mb-3">
                  <button 
                    onClick={() => handleWinnerSelect(match.id, match.teamAId)}
                    disabled={!isHost || currentRound.status === RoundStatus.SUBMITTED}
                    className={`flex-1 py-1 text-[7px] font-black uppercase tracking-widest border border-dashed transition-all ${match.winnerId === match.teamAId ? 'bg-white text-black border-white' : 'text-white/20 border-white/10'}`}
                  >
                    {match.winnerId === match.teamAId ? 'WINNER ✓' : 'SELECT WINNER'}
                  </button>
                  <div className="w-12 text-center text-[7px] font-black text-white/10">CRT {match.courtNumber}</div>
                  <button 
                    onClick={() => handleWinnerSelect(match.id, match.teamBId)}
                    disabled={!isHost || currentRound.status === RoundStatus.SUBMITTED}
