const QRModal: React.FC<{ url: string; onClose: () => void }> = ({ url, onClose }) => {
  const [qrData, setQrData] = useState<string>('');
  const [copied, setCopied] = useState(false);

  useEffect(() => {
    QRCode.toDataURL(url, { 
      width: 400, 
      margin: 1, 
      color: { dark: '#000000', light: '#ffffff' } 
    }).then(setQrData);
  }, [url]);

  const copyLink = () => {
    navigator.clipboard.writeText(url);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <Modal title="Invite Access" subtitle="Real-time observer node" onClose={onClose}>
      <div className="bg-white p-2 mb-6">
        {qrData ? <img src={qrData} alt="QR Code" className="w-48 h-48" /> : <div className="w-48 h-48 bg-white/10" />}
      </div>
      <div className="w-full space-y-4">
        <button 
          onClick={copyLink}
          className="w-full flex items-center justify-between p-3 border border-white/20 text-[9px] mono uppercase tracking-widest transition-colors hover:bg-white/5"
        >
          <span className="truncate mr-4 text-white/50 text-left">{url}</span>
          {copied ? <Check size={12} className="text-green-400" /> : <Copy size={12} />}
        </button>
        <Button onClick={onClose} variant="primary" className="w-full">CLOSE</Button>
      </div>
    </Modal>
  );
};

