const TeamSetupView: React.FC<{ event: Event; onConfirm: (teams: Team[]) => void; onBack: () => void }> = ({ event, onConfirm, onBack }) => {
  const [teams, setTeams] = useState<Team[]>(
    Array.from({ length: event.numberOfTeams }, (_, i) => ({
      id: nanoid(),
      name: `SQUAD ${i + 1}`,
      player1: '',
      player2: ''
