          </div>
        ))}
      </div>

      <div className="fixed bottom-0 left-0 right-0 p-6 bg-black border-t border-white/20 z-50">
        <Button onClick={() => onConfirm(teams)} className="w-full py-5" disabled={!isReady}>
          Begin Tournament
