export default function App() {
  const [view, setView] = useState<'LANDING' | 'CREATE' | 'TEAM_SETUP' | 'DASHBOARD'>('LANDING');
  const [activeEvent, setActiveEvent] = useState<Event | null>(null);

  useEffect(() => {
    const handleHash = () => {
      const hash = window.location.hash;
      if (hash.startsWith('#/event/')) {
        const id = hash.replace('#/event/', '');
        const ev = getEvent(id);
        if (ev) {
          setActiveEvent(ev);
          setView('DASHBOARD');
        }
      } else {
        setView('LANDING');
      }
    };
    window.addEventListener('hashchange', handleHash);
    handleHash();
    return () => window.removeEventListener('hashchange', handleHash);
  }, []);

  const handleCreateNew = () => setView('CREATE');

  const handleEventCreated = (ev: Event) => {
    setActiveEvent(ev);
    setView('TEAM_SETUP');
  };

  const handleTeamsConfirmed = (teams: Team[]) => {
    if (!activeEvent) return;
    const rounds = generateSchedule(teams, activeEvent.numberOfCourts);
    const updated = { ...activeEvent, teams, rounds };
    setActiveEvent(updated);
    saveEvent(updated);
    window.location.hash = `#/event/${updated.id}`;
    setView('DASHBOARD');
  };

  const handleEventUpdate = (updated: Event) => {
    setActiveEvent(updated);
    saveEvent(updated);
  };

  const handleResetEverything = () => {
    if (confirm("Are you sure you want to reset the event? This will remove everything and take you back to the home screen")) {
      window.location.hash = '';
      setView('LANDING');
      setActiveEvent(null);
    }
  };

  const handleBack = () => {
    if (view === 'CREATE') setView('LANDING');
    else if (view === 'TEAM_SETUP') setView('CREATE');
    else if (view === 'DASHBOARD') handleResetEverything();
  };

  const isHost = activeEvent ? getHostToken(activeEvent.id) === activeEvent.hostToken : false;

  return (
    <div className="min-h-screen relative text-white selection:bg-white selection:text-black bg-black">
      <NagaiBackground />
      <div className="relative z-10">
        {view === 'LANDING' && <LandingView onCreate={handleCreateNew} onResume={(id) => window.location.hash = `#/event/${id}`} />}
        {view === 'CREATE' && <CreateView onCreated={handleEventCreated} onBack={handleBack} />}
        {view === 'TEAM_SETUP' && activeEvent && <TeamSetupView event={activeEvent} onConfirm={handleTeamsConfirmed} onBack={handleBack} />}
        {view === 'DASHBOARD' && activeEvent && (
          <Dashboard 
            event={activeEvent} 
            onUpdate={handleEventUpdate} 
            isHost={isHost}
            onResetEvent={handleResetEverything}
          />
        )}
      </div>
    </div>
  );
}

import { Event, StandingRow, MatchStatus, RoundStatus } from '../types';

export function computeStandings(event: Event): StandingRow[] {
  const standings: Record<string, StandingRow> = {};

  // Initialize
  event.teams.forEach(team => {
    standings[team.id] = {
      rank: 0,
      teamId: team.id,
      teamName: team.name,
      wins: 0,
      losses: 0,
      pointsFor: 0,
      pointsAgainst: 0,
      diff: 0,
      gamesPlayed: 0,
      byeCount: 0
    };
  });

  // Process all submitted matches
  event.rounds.forEach(round => {
    if (round.status === RoundStatus.SUBMITTED) {
      round.matches.forEach(match => {
        if (match.status === MatchStatus.COMPLETE && match.scoreA !== null && match.scoreB !== null) {
          const tA = standings[match.teamAId];
          const tB = standings[match.teamBId];

          if (tA && tB) {
            tA.gamesPlayed++;
            tB.gamesPlayed++;
            tA.pointsFor += match.scoreA;
            tA.pointsAgainst += match.scoreB;
            tB.pointsFor += match.scoreB;
            tB.pointsAgainst += match.scoreA;

            if (match.scoreA > match.scoreB) {
              tA.wins++;
              tB.losses++;
            } else if (match.scoreB > match.scoreA) {
              tB.wins++;
              tA.losses++;
            }
          }
        }
      });
    }
  });

  // Calculate differentials
  Object.values(standings).forEach(s => {
    s.diff = s.pointsFor - s.pointsAgainst;
  });

  // Sort with tie-breakers
  const sorted = Object.values(standings).sort((a, b) => {
    // 1. Wins
    if (b.wins !== a.wins) return b.wins - a.wins;
    // 2. Point Diff
    if (b.diff !== a.diff) return b.diff - a.diff;
    // 3. Points For
    if (b.pointsFor !== a.pointsFor) return b.pointsFor - a.pointsFor;
    // Stability
    return a.teamName.localeCompare(b.teamName);
  });

  // Assign ranks
  return sorted.map((s, i) => ({ ...s, rank: i + 1 }));
}

import { Event } from '../types';

const STORAGE_KEY = 'pb_events_v1';

export function saveEvent(event: Event) {
  const events = getStoredEvents();
  events[event.id] = event;
  localStorage.setItem(STORAGE_KEY, JSON.stringify(events));
}

export function deleteEvent(id: string) {
  const events = getStoredEvents();
  delete events[id];
  localStorage.setItem(STORAGE_KEY, JSON.stringify(events));
  localStorage.removeItem(`host_token_${id}`);
}

export function getStoredEvents(): Record<string, Event> {
  const data = localStorage.getItem(STORAGE_KEY);
  return data ? JSON.parse(data) : {};
}

export function getEvent(id: string): Event | null {
  const events = getStoredEvents();
  return events[id] || null;
}

export function generateEventShareUrl(event: Event): string {
  return `${window.location.origin}${window.location.pathname}#/event/${event.id}`;
}

export function setHostToken(eventId: string, token: string) {
  localStorage.setItem(`host_token_${eventId}`, token);
}

export function getHostToken(eventId: string): string | null {
  return localStorage.getItem(`host_token_${eventId}`);
}

