export default function App() {
  const [view, setView] = useState<'LANDING' | 'CREATE' | 'TEAM_SETUP' | 'DASHBOARD'>('LANDING');
  const [activeEvent, setActiveEvent] = useState<Event | null>(null);

  useEffect(() => {
    const handleHash = () => {
      const hash = window.location.hash;
      if (hash.startsWith('#/event/')) {
        const id = hash.replace('#/event/', '');
        const ev = getEvent(id);
        if (ev) {
          setActiveEvent(ev);
          setView('DASHBOARD');
        }
      } else {
        setView('LANDING');
      }
    };
    window.addEventListener('hashchange', handleHash);
    handleHash();
    return () => window.removeEventListener('hashchange', handleHash);
  }, []);

  const handleCreateNew = () => setView('CREATE');

  const handleEventCreated = (ev: Event) => {
    setActiveEvent(ev);
    setView('TEAM_SETUP');
  };

  const handleTeamsConfirmed = (teams: Team[]) => {
    if (!activeEvent) return;
    const rounds = generateSchedule(teams, activeEvent.numberOfCourts);
    const updated = { ...activeEvent, teams, rounds };
    setActiveEvent(updated);
    saveEvent(updated);
    window.location.hash = `#/event/${updated.id}`;
    setView('DASHBOARD');
  };

  const handleEventUpdate = (updated: Event) => {
    setActiveEvent(updated);
    saveEvent(updated);
  };

  const handleResetEverything = () => {
    if (confirm("Are you sure you want to reset the event? This will remove everything and take you back to the home screen")) {
      if (activeEvent) {
        deleteEvent(activeEvent.id);
      }
      window.location.hash = '';
      setView('LANDING');
      setActiveEvent(null);
    }
  };

  const handleBack = () => {
    if (view === 'CREATE') setView('LANDING');
    else if (view === 'TEAM_SETUP') setView('CREATE');
    else if (view === 'DASHBOARD') handleResetEverything();
  };

  const isHost = activeEvent ? getHostToken(activeEvent.id) === activeEvent.hostToken : false;

  return (
    <div className="min-h-screen relative text-white selection:bg-white selection:text-black bg-black">
      <NagaiBackground />
      <div className="relative z-10">
        {view === 'LANDING' && <LandingView onCreate={handleCreateNew} onResume={(id) => window.location.hash = `#/event/${id}`} />}
        {view === 'CREATE' && <CreateView onCreated={handleEventCreated} onBack={handleBack} />}
        {view === 'TEAM_SETUP' && activeEvent && <TeamSetupView event={activeEvent} onConfirm={handleTeamsConfirmed} onBack={handleBack} />}
        {view === 'DASHBOARD' && activeEvent && (
          <Dashboard 
            event={activeEvent} 
            onUpdate={handleEventUpdate} 
            isHost={isHost}
            onResetEvent={handleResetEverything}
          />
        )}
      </div>
    </div>
  );
}

import { Team, Round, Match, MatchStatus, RoundStatus } from '../types';

export function generateSchedule(
  teams: Team[],
  numberOfCourts: number
): Round[] {
  const teamIds = teams.map(t => t.id);
  const isOdd = teamIds.length % 2 !== 0;
  if (isOdd) {
    teamIds.push('BYE');
  }

  const numTeams = teamIds.length;
  const numRounds = numTeams - 1;
  const half = numTeams / 2;

  const rounds: Round[] = [];

  for (let r = 0; r < numRounds; r++) {
    const roundMatches: Match[] = [];

    for (let i = 0; i < half; i++) {
      const teamA = teamIds[i];
      const teamB = teamIds[numTeams - 1 - i];

      // Exclude true BYEs from the match list
      if (teamA !== 'BYE' && teamB !== 'BYE') {
        roundMatches.push({
          id: `round-${r}-match-${i}`,
          courtNumber: 0, 
          teamAId: teamA,
          teamBId: teamB,
          scoreA: null, // Initialize as null to remove default 0
          scoreB: null, // Initialize as null to remove default 0
          status: MatchStatus.PENDING,
        });
      }
    }

    // Assign courts and waves
    roundMatches.forEach((match, index) => {
      match.courtNumber = (index % numberOfCourts) + 1;
      match.waveNumber = Math.floor(index / numberOfCourts) + 1;
    });

    rounds.push({
      id: `round-${r}`,
      roundNumber: r + 1,
      status: RoundStatus.NOT_STARTED,
      elapsedSeconds: 0,
      matches: roundMatches
    });

    // Rotate circle
    const last = teamIds.pop();
    if (last) {
      teamIds.splice(1, 0, last);
    }
  }

  return rounds;
}

