              />
              <input 
                type="text" placeholder="Player 2" 
                value={team.player2}
                onChange={e => updateTeam(i, 'player2', e.target.value)}
                className="w-full bg-transparent border-b border-white/20 p-2 outline-none text-[10px] font-bold uppercase tracking-[0.3em] focus:border-white"
              />
