          <span className="truncate mr-4 text-white/50 text-left">{url}</span>
          {copied ? <Check size={12} className="text-green-400" /> : <Copy size={12} />}
        </button>
        <Button onClick={onClose} variant="primary" className="w-full">CLOSE</Button>
