          <div>
            <label className="block text-[9px] font-black text-white/30 uppercase tracking-[0.4em] mb-3">Courts: {courts}</label>
            <input 
              type="range" min="1" max="12" value={courts} 
              onChange={e => setCourts(parseInt(e.target.value))}
              className="w-full accent-white" 
            />
          </div>
        </div>

        {/* Projection Box */}
        <div className="bg-white/5 border border-white/10 p-4 space-y-3">
          <div className="flex items-center justify-between">
            <h3 className="text-[9px] font-black uppercase tracking-[0.3em] text-white/50 flex items-center gap-2">
              <Info size={10} /> Round Robin Sequence
            </h3>
          </div>
          <div className="grid grid-cols-2 gap-y-4 gap-x-2">
            <div>
              <div className="text-[7px] font-black uppercase text-white/30 tracking-widest mb-1">Total Rounds</div>
              <div className="text-xl font-black italic">{projection.totalRounds}</div>
            </div>
            <div>
              <div className="text-[7px] font-black uppercase text-white/30 tracking-widest mb-1">Total Games</div>
              <div className="text-xl font-black italic">{projection.totalMatches}</div>
            </div>
            <div>
              <div className="text-[7px] font-black uppercase text-white/30 tracking-widest mb-1">Byes/Round</div>
              <div className="text-xl font-black italic">{projection.byes}</div>
            </div>
            <div>
              <div className="text-[7px] font-black uppercase text-white/30 tracking-widest mb-1">Waves/Round</div>
              <div className={`text-xl font-black italic ${projection.wavesPerRound > 1 ? 'text-orange-400' : 'text-white'}`}>
                {projection.wavesPerRound}
              </div>
            </div>
          </div>
          {projection.wavesPerRound > 1 && (
            <div className="pt-2 border-t border-white/10 mt-2">
              <p className="text-[8px] text-orange-400 font-bold uppercase tracking-widest leading-tight">
                Warning: Court shortage will trigger {projection.wavesPerRound} waves per round. Play time will increase significantly.
              </p>
            </div>
          )}
        </div>

        <div>
          <label className="block text-[9px] font-black text-white/30 uppercase tracking-[0.4em] mb-4">Target Points</label>
          <div className="flex">
            {[11, 15, 21].map(v => (
              <button 
                key={v}
                onClick={() => setPts(v)}
                className={`flex-1 py-3 font-black transition-all border ${pts === v ? 'bg-white text-black border-white' : 'bg-transparent text-white border-white/10'}`}
              >
                {v}
              </button>
            ))}
          </div>
        </div>

        <Button onClick={handleCreate} className="w-full py-5 mt-4">
          Generate Schedule
        </Button>
      </div>
    </div>
  );
};

const TeamSetupView: React.FC<{ event: Event; onConfirm: (teams: Team[]) => void; onBack: () => void }> = ({ event, onConfirm, onBack }) => {
  const [teams, setTeams] = useState<Team[]>(
    Array.from({ length: event.numberOfTeams }, (_, i) => ({
      id: nanoid(),
      name: `SQUAD ${i + 1}`,
      player1: '',
      player2: ''
    }))
  );

  const updateTeam = (idx: number, field: keyof Team, val: string) => {
    const next = [...teams];
    next[idx] = { ...next[idx], [field]: val };
    setTeams(next);
  };

  const isReady = teams.every(t => t.player1 && t.player2);

  return (
    <div className="max-w-md mx-auto p-6 page-transition">
      <header className="mb-10 mt-6 flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-black uppercase italic tracking-tighter">OPERATIVES</h1>
          <p className="text-white/30 text-[8px] font-bold uppercase tracking-[0.3em] mt-1">ID Required for {event.numberOfTeams} pairs</p>
        </div>
        <button onClick={onBack} className="p-2 border border-white/20 hover:bg-white/5 transition-colors"><ChevronLeft size={18} /></button>
      </header>

      <div className="space-y-8 mb-40">
        {teams.map((team, i) => (
          <div key={team.id} className="border-t border-white/20 pt-6">
            <div className="flex items-center justify-between mb-4">
              <span className="text-[9px] font-black text-white/30 tracking-[0.4em]">0{i + 1}</span>
              <input 
                type="text" 
                value={team.name}
                onChange={e => updateTeam(i, 'name', e.target.value)}
                className="text-right font-black text-xs outline-none bg-transparent uppercase tracking-widest text-white/50"
              />
            </div>
            <div className="grid grid-cols-1 gap-4">
              <input 
                type="text" placeholder="Player 1" 
                value={team.player1}
                onChange={e => updateTeam(i, 'player1', e.target.value)}
                className="w-full bg-transparent border-b border-white/20 p-2 outline-none text-[10px] font-bold uppercase tracking-[0.3em] focus:border-white"
              />
              <input 
                type="text" placeholder="Player 2" 
                value={team.player2}
                onChange={e => updateTeam(i, 'player2', e.target.value)}
                className="w-full bg-transparent border-b border-white/20 p-2 outline-none text-[10px] font-bold uppercase tracking-[0.3em] focus:border-white"
              />
            </div>
          </div>
        ))}
      </div>

      <div className="fixed bottom-0 left-0 right-0 p-6 bg-black border-t border-white/20 z-50 pb-safe">
        <Button onClick={() => onConfirm(teams)} className="w-full py-5" disabled={!isReady}>
          Begin Tournament
        </Button>
      </div>
    </div>
  );
};

const Dashboard: React.FC<{ 
  event: Event; 
  onUpdate: (ev: Event) => void;
  isHost: boolean;
  onResetEventTrigger: () => void;
  onGoHome: () => void;
}> = ({ event, onUpdate, isHost, onResetEventTrigger, onGoHome }) => {
  const [activeRoundIdx, setActiveRoundIdx] = useState(0);
  const [showStandings, setShowStandings] = useState(false);
  const [standingsTab, setStandingsTab] = useState<'RR' | 'PLAYOFFS'>('RR');
  const [showQR, setShowQR] = useState(false);
  const [currentTime, setCurrentTime] = useState(Date.now());
  const roundScrollRef = useRef<HTMLDivElement>(null);

  const currentRound = event.rounds[activeRoundIdx];
  const standings = useMemo(() => computeStandings(event), [event]);

  const playingTeamIds = new Set(currentRound?.matches.flatMap(m => [m.teamAId, m.teamBId]) || []);
  const byeTeam = event.teams.find(t => !playingTeamIds.has(t.id));

  useEffect(() => {
    const interval = setInterval(() => setCurrentTime(Date.now()), 1000);
    return () => clearInterval(interval);
  }, []);

  // Auto-scroll the round selector when activeRoundIdx changes
  useEffect(() => {
    if (roundScrollRef.current) {
      const activeButton = roundScrollRef.current.children[activeRoundIdx] as HTMLElement;
      if (activeButton) {
        roundScrollRef.current.scrollTo({
          left: activeButton.offsetLeft - (roundScrollRef.current.offsetWidth / 2) + (activeButton.offsetWidth / 2),
          behavior: 'smooth'
        });
      }
    }
  }, [activeRoundIdx]);

  const getTimerDisplay = (round: Round) => {
    if (!round) return "00:00";
    let seconds = round.elapsedSeconds;
    if (round.status === RoundStatus.IN_PROGRESS && round.startTimestamp) {
      seconds += Math.floor((currentTime - round.startTimestamp) / 1000);
    }
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const handleStartRound = () => {
    if (!isHost) return;
    const nextRounds = [...event.rounds];
    nextRounds[activeRoundIdx] = {
      ...nextRounds[activeRoundIdx],
      status: RoundStatus.IN_PROGRESS,
      startTimestamp: Date.now()
    };
    onUpdate({ ...event, rounds: nextRounds });
  };

  const handlePauseRound = () => {
    if (!isHost) return;
    const round = event.rounds[activeRoundIdx];
    const elapsedSinceStart = round.startTimestamp ? Math.floor((Date.now() - round.startTimestamp) / 1000) : 0;
    const nextRounds = [...event.rounds];
    nextRounds[activeRoundIdx] = {
      ...nextRounds[activeRoundIdx],
      status: RoundStatus.STOPPED,
      elapsedSeconds: round.elapsedSeconds + elapsedSinceStart,
      startTimestamp: undefined
    };
    onUpdate({ ...event, rounds: nextRounds });
  };

  const handleResetRound = () => {
    if (!isHost) return;
    if (!confirm('REBOOT ROUND? This wipes all scores and timer data for the current sequence.')) return;
    const nextRounds = [...event.rounds];
    nextRounds[activeRoundIdx] = {
      ...nextRounds[activeRoundIdx],
      status: RoundStatus.NOT_STARTED,
      elapsedSeconds: 0,
      startTimestamp: undefined,
      matches: nextRounds[activeRoundIdx].matches.map(m => ({
        ...m,
        scoreA: null,
        scoreB: null,
        winnerId: undefined,
        status: MatchStatus.PENDING
      }))
    };
    onUpdate({ ...event, rounds: nextRounds });
  };

  const handleWinnerSelect = (matchId: string, teamId: string) => {
    if (!isHost || currentRound.status === RoundStatus.SUBMITTED) return;
    const nextRounds = [...event.rounds];
    const matchIdx = nextRounds[activeRoundIdx].matches.findIndex(m => m.id === matchId);
    if (matchIdx === -1) return;

    const match = { ...nextRounds[activeRoundIdx].matches[matchIdx] };
    match.winnerId = teamId;
    nextRounds[activeRoundIdx].matches[matchIdx] = match;
    onUpdate({ ...event, rounds: nextRounds });
  };

  const handleScoreChange = (matchId: string, team: 'A' | 'B', val: string) => {
    if (!isHost) return;
    const cleanVal = val.replace(/[^0-9]/g, '').slice(0, 2);
    const score = cleanVal === '' ? null : parseInt(cleanVal);

    const nextRounds = [...event.rounds];
    const matchIdx = nextRounds[activeRoundIdx].matches.findIndex(m => m.id === matchId);
    if (matchIdx === -1) return;

    const match = { ...nextRounds[activeRoundIdx].matches[matchIdx] };

    if (!match.winnerId) {
      alert("SELECT WINNER BEFORE LOGGING SCORE.");
      return;
    }

    if (team === 'A') match.scoreA = score;
    else match.scoreB = score;

    match.status = (match.scoreA !== null && match.scoreB !== null) ? MatchStatus.COMPLETE : MatchStatus.PENDING;
    match.lastEditedAt = Date.now();

    nextRounds[activeRoundIdx].matches[matchIdx] = match;
    onUpdate({ ...event, rounds: nextRounds });
  };

  const handleSubmitScores = () => {
    if (!isHost) return;
    const nextRounds = [...event.rounds];
    nextRounds[activeRoundIdx] = {
      ...nextRounds[activeRoundIdx],
      status: RoundStatus.SUBMITTED
    };
    onUpdate({ ...event, rounds: nextRounds });
  };

  const shareResults = () => {
    if (navigator.share) {
      navigator.share({
        title: `${event.name} Node`,
        text: `Live status update for ${event.name}`,
        url: window.location.href
      });
    }
  };

  if (showStandings) {
    return (
      <div className="max-w-md mx-auto p-6 min-h-screen page-transition bg-black">
        <header className="flex items-center justify-between mb-8 mt-4">
          <h1 className="text-2xl font-black italic tracking-tighter uppercase">RANKINGS</h1>
          <div className="flex gap-2">
            <button onClick={shareResults} className="p-2 border border-white/20 active:bg-white active:text-black transition-all"><Share2 size={18} /></button>
            <button onClick={() => setShowStandings(false)} className="p-2 border border-white/20 active:bg-white active:text-black transition-all"><X size={20} /></button>
          </div>
        </header>

        <div className="flex border border-white/10 mb-8">
          <button 
            onClick={() => setStandingsTab('RR')}
            className={`flex-1 py-3 text-[9px] font-black tracking-widest uppercase ${standingsTab === 'RR' ? 'bg-white text-black' : 'text-white/40'}`}
          >
            ROUND ROBIN
          </button>
          <button 
            onClick={() => setStandingsTab('PLAYOFFS')}
            className={`flex-1 py-3 text-[9px] font-black tracking-widest uppercase ${standingsTab === 'PLAYOFFS' ? 'bg-white text-black' : 'text-white/40'}`}
          >
            PLAYOFFS
          </button>
        </div>

        {standingsTab === 'RR' ? (
          <div className="border border-white/20">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-white/5 text-white/30 text-[8px] font-black uppercase tracking-[0.3em]">
                  <th className="px-4 py-3">RK</th>
                  <th className="px-4 py-3">SQUAD</th>
                  <th className="px-4 py-3 text-center">W/L</th>
                  <th className="px-4 py-3 text-center">PTS</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-white/10">
                {standings.map(row => {
                  const teamData = event.teams.find(t => t.id === row.teamId);
                  return (
                    <tr key={row.teamId}>
                      <td className="px-4 py-6 font-black text-xs italic">#{row.rank}</td>
                      <td className="px-4 py-6">
                        <div className="font-bold text-[8px] uppercase tracking-widest leading-relaxed">
                          {teamData?.player1} & {teamData?.player2}
                        </div>
                      </td>
                      <td className="px-4 py-6 text-center text-[8px] mono text-white/50">{row.wins}-{row.losses}</td>
                      <td className="px-4 py-6 text-center font-black text-xs tabular-nums">{row.pointsFor}</td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        ) : (
          <div className="text-center p-12 text-white/20 text-[9px] uppercase tracking-widest leading-relaxed">
            Playoff sequence pending completion of Round Robin.
          </div>
        )}
      </div>
    );
  }

  return (
    <div className="flex flex-col h-screen overflow-hidden page-transition bg-black">
      {showQR && <QRModal url={generateEventShareUrl(event)} onClose={() => setShowQR(false)} />}

      <header className="px-6 py-3 border-b border-white/10 flex items-center justify-between bg-black z-[100]">
        <div className="flex items-center gap-4">
          <button onClick={onGoHome} className="p-2 border border-white/10 active:bg-white active:text-black transition-all" title="Circuit Home">
            <ChevronLeft size={16} />
          </button>
          <div className="flex flex-col">
            <h1 className="text-[10px] font-black italic tracking-tighter uppercase text-white/80">{event.name}</h1>
            <div className="flex items-center gap-1.5">
              <span className="w-1 h-1 bg-green-500 rounded-full animate-pulse"></span>
              <span className="text-[7px] font-bold text-white/30 uppercase tracking-widest">Active Node</span>
            </div>
          </div>
        </div>
        <div className="flex gap-2">
          <button onClick={() => setShowQR(true)} className="p-2 border border-white/10 active:bg-white active:text-black transition-all"><QrCode size={12} /></button>
          <button onClick={() => setShowStandings(true)} className="p-2 border border-white/10 active:bg-white active:text-black transition-all"><Trophy size={12} /></button>
          <button 
            onClick={onResetEventTrigger} 
            className="px-3 py-1.5 border border-red-500 text-red-500 text-[8px] font-black uppercase tracking-widest hover:bg-red-500 hover:text-white transition-all"
          >
            RESET
          </button>
        </div>
      </header>

      <main className="flex-1 overflow-y-auto px-4 pt-4 pb-[20rem] no-scrollbar">
        <div className="px-2 mb-6">
          <div className="flex items-center justify-between mb-1">
             <div className="text-[7px] font-black text-white/20 uppercase tracking-[0.4em]">Chronometer</div>
             <div className="text-[7px] font-black text-white/20 uppercase tracking-[0.4em]">Round {currentRound?.roundNumber}</div>
          </div>
          <div className="flex items-center justify-between mb-4">
             <div className="text-4xl font-black italic tracking-tighter tabular-nums">{getTimerDisplay(currentRound)}</div>
             {isHost && (
              <div className="flex gap-1.5">
                <button 
                  onClick={currentRound?.status === RoundStatus.IN_PROGRESS ? handlePauseRound : handleStartRound} 
                  className="p-3 border border-white/20 flex items-center justify-center min-w-[44px]"
                >
                  {currentRound?.status === RoundStatus.IN_PROGRESS ? <Pause size={14} fill="white" /> : <Play size={14} fill="white" />}
                </button>
                <button 
                  onClick={handleResetRound} 
                  className="p-3 border border-white/20 flex items-center justify-center min-w-[44px]"
                  title="Reset Round Data"
                >
                  <RotateCcw size={14} />
                </button>
              </div>
             )}
          </div>

          {byeTeam && (
             <div className="border border-white/10 p-2 flex items-center justify-between bg-white/[0.02] border-dashed">
                <div className="text-[7px] font-black text-white/30 uppercase tracking-widest">BYE SQUAD</div>
                <div className="text-[8px] font-black uppercase tracking-widest truncate">{byeTeam.player1} & {byeTeam.player2}</div>
             </div>
          )}
        </div>

        <div className="space-y-12">
          {currentRound?.matches.map(match => {
            const teamA = event.teams.find(t => t.id === match.teamAId);
            const teamB = event.teams.find(t => t.id === match.teamBId);
            return (
              <div key={match.id} className="page-transition">
                <div className="flex items-center justify-between px-2 mb-3">
                  <button 
                    onClick={() => handleWinnerSelect(match.id, match.teamAId)}
                    disabled={!isHost || currentRound.status === RoundStatus.SUBMITTED}
                    className={`flex-1 py-1.5 text-[7px] font-black uppercase tracking-widest border border-dashed transition-all ${match.winnerId === match.teamAId ? 'bg-white text-black border-white' : 'text-white/20 border-white/10'}`}
                  >
                    {match.winnerId === match.teamAId ? 'WINNER ✓' : 'SELECT WINNER'}
                  </button>
                  <div className="w-12 text-center text-[7px] font-black text-white/10 uppercase tracking-tighter">CRT {match.courtNumber}</div>
                  <button 
                    onClick={() => handleWinnerSelect(match.id, match.teamBId)}
                    disabled={!isHost || currentRound.status === RoundStatus.SUBMITTED}
                    className={`flex-1 py-1.5 text-[7px] font-black uppercase tracking-widest border border-dashed transition-all ${match.winnerId === match.teamBId ? 'bg-white text-black border-white' : 'text-white/20 border-white/10'}`}
                  >
                    {match.winnerId === match.teamBId ? 'WINNER ✓' : 'SELECT WINNER'}
                  </button>
                </div>

                <div className="flex items-start justify-between px-2 mb-3 pb-2">
                  <div className="flex-1">
                    <div className="text-[8px] font-black uppercase tracking-wider leading-tight text-white/80">{teamA?.player1} & {teamA?.player2}</div>
                  </div>
                  <div className="px-4 text-[7px] font-black text-white/20 italic tracking-widest self-center shrink-0">VS</div>
                  <div className="flex-1 text-right">
                    <div className="text-[8px] font-black uppercase tracking-wider leading-tight text-white/80">{teamB?.player1} & {teamB?.player2}</div>
                  </div>
                </div>

                <div className="flex items-center justify-center gap-6">
                  <input 
                    type="text"
                    inputMode="numeric"
                    placeholder="—"
                    value={match.scoreA === null ? '' : match.scoreA} 
                    onChange={e => handleScoreChange(match.id, 'A', e.target.value)}
                    disabled={!isHost || currentRound.status === RoundStatus.SUBMITTED || !match.winnerId}
                    className="w-16 h-16 bg-white/5 border border-white/10 text-center text-2xl font-black italic outline-none focus:border-white disabled:opacity-10 text-white" 
                  />
                  <div className="text-white/5 text-[7px] font-black italic tracking-[0.4em]">PTS</div>
                  <input 
                    type="text"
                    inputMode="numeric"
                    placeholder="—"
                    value={match.scoreB === null ? '' : match.scoreB} 
                    onChange={e => handleScoreChange(match.id, 'B', e.target.value)}
                    disabled={!isHost || currentRound.status === RoundStatus.SUBMITTED || !match.winnerId}
                    className="w-16 h-16 bg-white/5 border border-white/10 text-center text-2xl font-black italic outline-none focus:border-white disabled:opacity-10 text-white" 
                  />
                </div>
              </div>
            );
          })}
        </div>
      </main>

      {/* Footer specifically tuned for mobile accessibility */}
      <footer className="fixed bottom-0 left-0 right-0 bg-black border-t border-white/10 z-[200] pb-safe">
        {isHost && currentRound?.status !== RoundStatus.SUBMITTED && (
           <button 
             onClick={handleSubmitScores}
             disabled={currentRound?.status === RoundStatus.IN_PROGRESS}
             className="w-full py-5 text-[9px] font-black uppercase tracking-[0.4em] bg-white text-black active:invert disabled:opacity-50"
           >
             SUBMIT ROUND LOGS
           </button>
        )}

        {/* Horizontal Round Scroller */}
        <div 
          ref={roundScrollRef}
          className="px-6 py-4 flex gap-2 overflow-x-auto no-scrollbar scroll-smooth snap-x snap-mandatory bg-black"
        >
          {event.rounds.map((r, idx) => (
            <button 
              key={r.id} 
              onClick={() => setActiveRoundIdx(idx)}
              className={`flex-shrink-0 w-12 h-12 flex items-center justify-center transition-all border snap-center relative ${
                activeRoundIdx === idx 
                  ? 'bg-white text-black border-white shadow-[0_0_20px_rgba(255,255,255,0.15)]' 
                  : 'bg-transparent text-white/30 border-white/10'
              }`}
            >
              <span className="text-[11px] font-black italic tabular-nums">{r.roundNumber}</span>
              {r.status === RoundStatus.SUBMITTED && (
                <div className="absolute top-0 right-0 bg-white text-black p-0.5"><Check size={6} strokeWidth={5} /></div>
              )}
            </button>
          ))}
          {/* Spacer for comfortable scrolling */}
          <div className="flex-shrink-0 w-4" />
        </div>
      </footer>
    </div>
  );
};

export default function App() {
  const [view, setView] = useState<'LANDING' | 'CREATE' | 'TEAM_SETUP' | 'DASHBOARD'>('LANDING');
  const [activeEvent, setActiveEvent] = useState<Event | null>(null);
  const [showResetConfirm, setShowResetConfirm] = useState(false);

  useEffect(() => {
    const handleHash = () => {
      const hash = window.location.hash;
      if (hash.startsWith('#/event/')) {
        const id = hash.replace('#/event/', '');
        const ev = getEvent(id);
        if (ev) {
          setActiveEvent(ev);
          setView('DASHBOARD');
        } else {
           window.location.hash = '';
           setView('LANDING');
        }
      } else {
        setView('LANDING');
      }
    };
    window.addEventListener('hashchange', handleHash);
    handleHash();
    return () => window.removeEventListener('hashchange', handleHash);
  }, []);

  const handleCreateNew = () => setView('CREATE');

  const handleEventCreated = (ev: Event) => {
    setActiveEvent(ev);
    setView('TEAM_SETUP');
  };

  const handleTeamsConfirmed = (teams: Team[]) => {
    if (!activeEvent) return;
    const rounds = generateSchedule(teams, activeEvent.numberOfCourts);
    const updated = { ...activeEvent, teams, rounds };
    setActiveEvent(updated);
    saveEvent(updated);
    window.location.hash = `#/event/${updated.id}`;
    setView('DASHBOARD');
  };

  const handleEventUpdate = (updated: Event) => {
    setActiveEvent(updated);
    saveEvent(updated);
  };

  const handleResetEverything = () => {
    if (activeEvent) {
      deleteEvent(activeEvent.id);
    }
    window.location.hash = '';
    setActiveEvent(null);
    setView('LANDING');
    setShowResetConfirm(false);
  };

  const handleGoHome = () => {
    window.location.hash = '';
    setActiveEvent(null);
    setView('LANDING');
  };

  const handleBack = () => {
    if (view === 'CREATE') setView('LANDING');
    else if (view === 'TEAM_SETUP') setView('CREATE');
    else if (view === 'DASHBOARD') setShowResetConfirm(true);
  };

  const isHost = activeEvent ? getHostToken(activeEvent.id) === activeEvent.hostToken : false;

  return (
    <div className="min-h-screen relative text-white selection:bg-white selection:text-black bg-black">
      <NagaiBackground />
      <div className="relative z-10">
        {showResetConfirm && (
          <ConfirmResetModal 
            onConfirm={handleResetEverything} 
            onCancel={() => setShowResetConfirm(false)} 
          />
        )}

        {view === 'LANDING' && <LandingView onCreate={handleCreateNew} onResume={(id) => window.location.hash = `#/event/${id}`} />}
        {view === 'CREATE' && <CreateView onCreated={handleEventCreated} onBack={handleBack} />}
        {view === 'TEAM_SETUP' && activeEvent && <TeamSetupView event={activeEvent} onConfirm={handleTeamsConfirmed} onBack={handleBack} />}
        {view === 'DASHBOARD' && activeEvent && (
          <Dashboard 
            event={activeEvent} 
            onUpdate={handleEventUpdate} 
            isHost={isHost}
            onResetEventTrigger={() => setShowResetConfirm(true)}
            onGoHome={handleGoHome}
          />
        )}
      </div>
    </div>
  );
}

