  event: Event; 
  onUpdate: (ev: Event) => void;
  isHost: boolean;
  onResetEventTrigger: () => void;
  onGoHome: () => void;
}> = ({ event, onUpdate, isHost, onResetEventTrigger, onGoHome }) => {
